-- ============================================================================
-- PHASE 2: REFERENCE TABLES
-- ============================================================================

-- Roles Table
CREATE TABLE Roles (
    RoleID INT IDENTITY(1,1) PRIMARY KEY,
    RoleName VARCHAR(50) UNIQUE NOT NULL
);

INSERT INTO Roles (RoleName)
VALUES ('Admin'), ('Recruiter'), ('Candidate');
GO

-- Application Status Table
CREATE TABLE ApplicationStatus (
    StatusID INT IDENTITY(1,1) PRIMARY KEY,
    StatusName VARCHAR(30) UNIQUE NOT NULL
);

INSERT INTO ApplicationStatus (StatusName)
VALUES
('Applied'),
('Screening'),
('Interview'),
('Hired'),
('Rejected'),
('Withdrawn'),
('Invited');
GO

-- Status Transitions Table (State Machine)
CREATE TABLE ApplicationStatusTransitions (
    FromStatusID INT,
    ToStatusID INT,
    PRIMARY KEY (FromStatusID, ToStatusID),
    FOREIGN KEY (FromStatusID) REFERENCES ApplicationStatus(StatusID),
    FOREIGN KEY (ToStatusID) REFERENCES ApplicationStatus(StatusID)
);

-- Valid Transitions
INSERT INTO ApplicationStatusTransitions VALUES 
(1, 2), -- Applied → Screening
(2, 3), -- Screening → Interview
(2, 5), -- Screening → Rejected
(3, 4), -- Interview → Hired
(3, 5), -- Interview → Rejected
(1, 6), -- Applied → Withdrawn
(2, 6), -- Screening → Withdrawn
(3, 6), -- Interview → Withdrawn
(7, 1), -- Invited → Applied
(7, 6); -- Invited → Withdrawn
GO

-- ============================================================================
-- PHASE 3: USER & ENTITY TABLES
-- ============================================================================

-- Users Table
CREATE TABLE Users (
    UserID INT IDENTITY(1,1) PRIMARY KEY,
    Username VARCHAR(50) UNIQUE NOT NULL,
    Email NVARCHAR(200) UNIQUE NOT NULL,              -- FIX-05: widened for CLR
    PasswordHash NVARCHAR(500) NOT NULL,              -- FIX-05: widened for PBKDF2
    SessionToken NVARCHAR(300) NULL,                  -- FIX-05: CLR integration
    LastLogin DATETIME NULL,                          -- FIX-05: CLR integration
    RoleID INT NOT NULL,
    CreatedAt DATETIME DEFAULT GETDATE(),
    IsActive BIT DEFAULT 1,
    FOREIGN KEY (RoleID) REFERENCES Roles(RoleID),
    CONSTRAINT CHK_Email_Format CHECK (Email LIKE '%_@_%._%')
    -- Note: CHK_Email_Format will be replaced by CLR trigger trg_ValidateEmail_OnInsert
);
GO

-- Candidates Table
CREATE TABLE Candidates (
    CandidateID INT IDENTITY(1,1) PRIMARY KEY,
    UserID INT UNIQUE NOT NULL,
    FullName VARCHAR(100) NOT NULL,
    Location VARCHAR(100),
    YearsOfExperience INT CHECK (YearsOfExperience >= 0) DEFAULT 0,
    PreferredLocations NVARCHAR(500) NULL,            -- FIX-08: for fn_LocationMatch
    ResumeFile VARBINARY(MAX) NULL,                   -- FIX-12: CLR resume parsing
    ResumeFileName NVARCHAR(255) NULL,                -- FIX-12: CLR resume parsing
    ResumeText NVARCHAR(MAX) NULL,                    -- FIX-12: extracted by CLR
    ExtractedSkills NVARCHAR(MAX) NULL,               -- FIX-12: CLR ExtractSkills output
    LinkedInURL NVARCHAR(500) NULL,                   -- FIX-12: CLR VerifyLinkedInProfile
    Timezone NVARCHAR(100) NULL,                      -- FIX-12: CLR timezone functions
    CreatedAt DATETIME DEFAULT GETDATE(),
    FOREIGN KEY (UserID) REFERENCES Users(UserID) ON DELETE CASCADE,
    CONSTRAINT CHK_FullName_NotEmpty CHECK (LEN(TRIM(FullName)) > 0)
);
GO

-- Recruiters Table
CREATE TABLE Recruiters (
    RecruiterID INT IDENTITY(1,1) PRIMARY KEY,
    UserID INT UNIQUE NOT NULL,
    Department VARCHAR(100),
    FOREIGN KEY (UserID) REFERENCES Users(UserID) ON DELETE CASCADE
);
GO

-- Candidate Documents Table
CREATE TABLE CandidateDocuments (
    DocumentID INT IDENTITY(1,1) PRIMARY KEY,
    CandidateID INT NOT NULL,
    DocumentType VARCHAR(50) CHECK (DocumentType IN ('Resume', 'CoverLetter', 'Certificate')),
    FilePath NVARCHAR(500),
    UploadedAt DATETIME DEFAULT GETDATE(),
    FOREIGN KEY (CandidateID) REFERENCES Candidates(CandidateID) ON DELETE CASCADE
);
GO

-- ============================================================================
-- PHASE 4: SKILLS & MATCHING
-- ============================================================================

-- Skills Table
CREATE TABLE Skills (
    SkillID INT IDENTITY(1,1) PRIMARY KEY,
    SkillName VARCHAR(100) UNIQUE NOT NULL
);
GO

-- Candidate Skills (with proficiency)
CREATE TABLE CandidateSkills (
    CandidateID INT,
    SkillID INT,
    ProficiencyLevel INT CHECK (ProficiencyLevel BETWEEN 1 AND 10),
    PRIMARY KEY (CandidateID, SkillID),
    FOREIGN KEY (CandidateID) REFERENCES Candidates(CandidateID) ON DELETE CASCADE,
    FOREIGN KEY (SkillID) REFERENCES Skills(SkillID)
);
GO

-- ============================================================================
-- PHASE 5: JOB POSTINGS
-- ============================================================================

-- Job Postings Table
CREATE TABLE JobPostings (
    JobID INT IDENTITY(1,1) PRIMARY KEY,
    JobTitle VARCHAR(150) NOT NULL,
    Description NVARCHAR(MAX),
    Location VARCHAR(100),
    MinExperience INT CHECK (MinExperience >= 0) DEFAULT 0,
    Vacancies INT CHECK (Vacancies >= 0),
    CreatedAt DATETIME DEFAULT GETDATE(),
    IsActive BIT DEFAULT 1,
    IsDeleted BIT DEFAULT 0,
    CreatedBy INT,
    FOREIGN KEY (CreatedBy) REFERENCES Users(UserID)
);
GO

-- Job Skills Requirements
CREATE TABLE JobSkills (
    JobID INT,
    SkillID INT,
    IsMandatory BIT DEFAULT 0,
    MinProficiency INT CHECK (MinProficiency BETWEEN 1 AND 10),
    PRIMARY KEY (JobID, SkillID),
    FOREIGN KEY (JobID) REFERENCES JobPostings(JobID) ON DELETE CASCADE,
    FOREIGN KEY (SkillID) REFERENCES Skills(SkillID)
);
GO

-- ============================================================================
-- PHASE 6: APPLICATIONS & WORKFLOW
-- ============================================================================

-- Applications Table
CREATE TABLE Applications (
    ApplicationID INT IDENTITY(1,1) PRIMARY KEY,
    CandidateID INT NOT NULL,
    JobID INT NOT NULL,
    StatusID INT NOT NULL,
    AppliedDate DATETIME DEFAULT GETDATE(),
    StatusChangedAt DATETIME DEFAULT GETDATE(),
    WithdrawnAt DATETIME NULL,
    WithdrawalReason NVARCHAR(500) NULL,
    RejectionReason NVARCHAR(200) NULL,
    IsDeleted BIT DEFAULT 0,
    FOREIGN KEY (CandidateID) REFERENCES Candidates(CandidateID) ON DELETE CASCADE,
    FOREIGN KEY (JobID) REFERENCES JobPostings(JobID),
    FOREIGN KEY (StatusID) REFERENCES ApplicationStatus(StatusID),
    CONSTRAINT UQ_Application UNIQUE (CandidateID, JobID)
);
GO

-- Application Status History Table
CREATE TABLE ApplicationStatusHistory (
    HistoryID INT IDENTITY(1,1) PRIMARY KEY,
    ApplicationID INT NOT NULL,
    FromStatusID INT,
    ToStatusID INT NOT NULL,
    ChangedBy INT NOT NULL,
    ChangedAt DATETIME DEFAULT GETDATE(),
    Notes NVARCHAR(500),
    FOREIGN KEY (ApplicationID) REFERENCES Applications(ApplicationID) ON DELETE CASCADE,
    FOREIGN KEY (FromStatusID) REFERENCES ApplicationStatus(StatusID),
    FOREIGN KEY (ToStatusID) REFERENCES ApplicationStatus(StatusID),
    FOREIGN KEY (ChangedBy) REFERENCES Users(UserID)
);
GO

-- ============================================================================
-- PHASE 7: INTERVIEWS & FEEDBACK
-- ============================================================================

-- Interview Schedules Table
CREATE TABLE InterviewSchedules (
    ScheduleID INT IDENTITY(1,1) PRIMARY KEY,
    ApplicationID INT NOT NULL,
    RecruiterID INT NOT NULL,
    InterviewStart DATETIME NOT NULL,
    InterviewEnd DATETIME NOT NULL,
    CandidateConfirmed BIT DEFAULT 0,
    CreatedAt DATETIME DEFAULT GETDATE(),
    FOREIGN KEY (ApplicationID) REFERENCES Applications(ApplicationID) ON DELETE CASCADE,
    FOREIGN KEY (RecruiterID) REFERENCES Recruiters(RecruiterID)
);
GO

-- Interview Feedback Table
CREATE TABLE InterviewFeedback (
    FeedbackID INT IDENTITY(1,1) PRIMARY KEY,
    ApplicationID INT NOT NULL,
    InterviewerID INT NOT NULL,
    TechnicalScore INT CHECK (TechnicalScore BETWEEN 0 AND 10),
    CommunicationScore INT CHECK (CommunicationScore BETWEEN 0 AND 10),
    CultureFitScore INT CHECK (CultureFitScore BETWEEN 0 AND 10),
    Recommendation VARCHAR(20) CHECK (Recommendation IN ('Hire', 'Hold', 'Reject')),
    Comments NVARCHAR(500),
    SentimentScore FLOAT NULL,                        -- FIX-12: CLR CalculateSentiment
    CreatedAt DATETIME DEFAULT GETDATE(),
    FOREIGN KEY (ApplicationID) REFERENCES Applications(ApplicationID) ON DELETE CASCADE,
    FOREIGN KEY (InterviewerID) REFERENCES Users(UserID)
);
GO

-- ============================================================================
-- PHASE 8: AUDIT & LOGGING
-- ============================================================================

