-- ============================================================================
-- PHASE 12: STORED PROCEDURES
-- ============================================================================

-- Update Application Status
CREATE PROCEDURE sp_UpdateApplicationStatus
    @ApplicationID INT,
    @NewStatusID INT,
    @ChangedBy INT,
    @Notes NVARCHAR(500) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @CurrentStatusID INT;

    -- Get current status
    SELECT @CurrentStatusID = StatusID
    FROM Applications
    WHERE ApplicationID = @ApplicationID;

    IF @CurrentStatusID IS NULL
    BEGIN
        RAISERROR ('Application not found.', 16, 1);
        RETURN;
    END

    -- Prevent changes after terminal states
    IF @CurrentStatusID IN (4, 5)
    BEGIN
        RAISERROR ('Cannot modify a terminal application state.', 16, 1);
        RETURN;
    END

    -- Validate transition
    IF NOT EXISTS (
        SELECT 1
        FROM ApplicationStatusTransitions
        WHERE FromStatusID = @CurrentStatusID
          AND ToStatusID = @NewStatusID
    )
    BEGIN
        RAISERROR ('Invalid application status transition.', 16, 1);
        RETURN;
    END

    -- Perform update
    UPDATE Applications
    SET StatusID = @NewStatusID,
        StatusChangedAt = GETDATE()
    WHERE ApplicationID = @ApplicationID;

    -- Record in status history
    INSERT INTO ApplicationStatusHistory (ApplicationID, FromStatusID, ToStatusID, ChangedBy, Notes)
    VALUES (@ApplicationID, @CurrentStatusID, @NewStatusID, @ChangedBy, @Notes);
END;
GO

-- Withdraw Application
CREATE PROCEDURE sp_WithdrawApplication
    @ApplicationID INT,
    @CandidateID INT,
    @Reason NVARCHAR(500)
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @CurrentStatusID INT, @WithdrawnStatusID INT, @UserID INT;

    SELECT @WithdrawnStatusID = StatusID FROM ApplicationStatus WHERE StatusName = 'Withdrawn';
    
    -- Get both the Status AND the UserID for the history log
    SELECT @CurrentStatusID = a.StatusID, @UserID = c.UserID
    FROM Applications a
    JOIN Candidates c ON a.CandidateID = c.CandidateID
    WHERE a.ApplicationID = @ApplicationID AND a.CandidateID = @CandidateID;

    IF @CurrentStatusID IS NULL
    BEGIN
        RAISERROR ('Application not found or does not belong to candidate.', 16, 1);
        RETURN;
    END

    -- Cannot withdraw if already hired or rejected
    IF @CurrentStatusID IN (4, 5)
    BEGIN
        RAISERROR ('Cannot withdraw application in final state.', 16, 1);
        RETURN;
    END

    -- Update application
    UPDATE Applications
    SET StatusID = @WithdrawnStatusID,
        WithdrawnAt = GETDATE(),
        WithdrawalReason = @Reason,
        StatusChangedAt = GETDATE()
    WHERE ApplicationID = @ApplicationID;

    -- Record in history
    INSERT INTO ApplicationStatusHistory (ApplicationID, FromStatusID, ToStatusID, ChangedBy, Notes)
    VALUES (@ApplicationID, @CurrentStatusID, @WithdrawnStatusID, @UserID, 'Withdrawn: ' + @Reason);
END;
GO

-- Concurrency-Safe Hiring
CREATE PROCEDURE sp_HireCandidate
    @ApplicationID INT,
    @RecruiterID INT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @JobID INT;
    DECLARE @Vacancies INT;
    DECLARE @CurrentStatusID INT;
    DECLARE @HiredStatusID INT;

    SELECT @HiredStatusID = StatusID FROM ApplicationStatus WHERE StatusName = 'Hired';

    BEGIN TRANSACTION;

    BEGIN TRY
        -- Lock both application and job posting rows
        SELECT 
            @JobID = a.JobID,
            @CurrentStatusID = a.StatusID
        FROM Applications a WITH (UPDLOCK, HOLDLOCK)
        WHERE a.ApplicationID = @ApplicationID;

        SELECT @Vacancies = Vacancies
        FROM JobPostings WITH (UPDLOCK, HOLDLOCK)
        WHERE JobID = @JobID;

        -- FIX-04: Check terminal states before lock
        IF @CurrentStatusID IN (4, 5)  -- Hired=4, Rejected=5
        BEGIN
            RAISERROR('Cannot hire candidate already in terminal state (Hired/Rejected).', 16, 1);
            ROLLBACK TRANSACTION;
            RETURN;
        END

        -- Validate candidate is in Interview stage
        IF @CurrentStatusID <> 3
        BEGIN
            RAISERROR('Candidate not in Interview stage.', 16, 1);
            ROLLBACK TRANSACTION;
            RETURN;
        END

        -- Check remaining vacancies
        IF @Vacancies <= 0
        BEGIN
            RAISERROR('No vacancies remaining for this job.', 16, 1);
            ROLLBACK TRANSACTION;
            RETURN;
        END

        -- Update application to Hired
        UPDATE Applications
        SET StatusID = @HiredStatusID,
            StatusChangedAt = GETDATE()
        WHERE ApplicationID = @ApplicationID;

        -- Record in history
        INSERT INTO ApplicationStatusHistory (ApplicationID, FromStatusID, ToStatusID, ChangedBy, Notes)
        VALUES (@ApplicationID, @CurrentStatusID, @HiredStatusID, @RecruiterID, 'Hired by recruiter');

        -- Decrement vacancies
        UPDATE JobPostings
        SET Vacancies = Vacancies - 1
        WHERE JobID = @JobID;

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        ROLLBACK TRANSACTION;
        THROW;
    END CATCH
END;
GO

-- Auto-Reject Based on Minimum Experience
CREATE PROCEDURE sp_AutoRejectUnqualified
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @RejectedStatusID INT;

    SELECT @RejectedStatusID = StatusID 
    FROM ApplicationStatus 
    WHERE StatusName = 'Rejected';

    -- Update applications where candidate doesn't meet minimum experience
    UPDATE Applications
    SET StatusID = @RejectedStatusID,
        RejectionReason = 'Does not meet minimum experience requirement',
        StatusChangedAt = GETDATE()
    WHERE ApplicationID IN (
        SELECT a.ApplicationID
        FROM Applications a
        JOIN Candidates c ON a.CandidateID = c.CandidateID
        JOIN JobPostings j ON a.JobID = j.JobID
        WHERE c.YearsOfExperience < j.MinExperience
          AND a.StatusID = 1
    );
END;
GO

-- Archive Old Data
CREATE PROCEDURE sp_ArchiveOldData
AS
BEGIN
    SET NOCOUNT ON;

    -- 1. ARCHIVE JOB POSTINGS
    INSERT INTO JobPostingsArchive (JobID, JobTitle, Description, Location, Vacancies, CreatedAt)
    SELECT JobID, JobTitle, Description, Location, Vacancies, CreatedAt
    FROM JobPostings
    WHERE (CreatedAt < DATEADD(MONTH, -6, GETDATE()) OR IsDeleted = 1)
      AND JobID NOT IN (SELECT JobID FROM JobPostingsArchive);

    -- 2. ARCHIVE APPLICATIONS ATTACHED TO ARCHIVED JOBS
    INSERT INTO ApplicationsArchive (ApplicationID, CandidateID, JobID, StatusID, AppliedDate)
    SELECT ApplicationID, CandidateID, JobID, StatusID, AppliedDate
    FROM Applications
    WHERE JobID IN (SELECT JobID FROM JobPostingsArchive)
      AND ApplicationID NOT IN (SELECT ApplicationID FROM ApplicationsArchive);

    -- 3. ARCHIVE OLD REJECTED APPLICATIONS
    INSERT INTO ApplicationsArchive (ApplicationID, CandidateID, JobID, StatusID, AppliedDate)
    SELECT ApplicationID, CandidateID, JobID, StatusID, AppliedDate
    FROM Applications
    WHERE StatusID = 5
      AND AppliedDate < DATEADD(YEAR, -1, GETDATE())
      AND ApplicationID NOT IN (SELECT ApplicationID FROM ApplicationsArchive);

    -- 4. CLEAN UP / SOFT DELETE
    UPDATE JobPostings
    SET IsDeleted = 1, IsActive = 0
    WHERE JobID IN (SELECT JobID FROM JobPostingsArchive);

    UPDATE Applications
    SET IsDeleted = 1
    WHERE ApplicationID IN (SELECT ApplicationID FROM ApplicationsArchive);

    PRINT 'Archival process completed successfully.';
END;
GO

-- Anonymize Archived Candidates
CREATE PROCEDURE sp_AnonymizeArchivedCandidates
AS
BEGIN
    SET NOCOUNT ON;

    UPDATE Candidates
    SET FullName = CONCAT('Candidate_', CandidateID),
        Location = 'Anonymized'
    WHERE CandidateID IN (
        SELECT DISTINCT CandidateID
        FROM ApplicationsArchive
    );

    UPDATE Users
    SET Email = CONCAT('anonymized_', UserID, '@archived.local')
    WHERE UserID IN (
        SELECT DISTINCT c.UserID
        FROM Candidates c
        WHERE c.CandidateID IN (
            SELECT DISTINCT CandidateID
            FROM ApplicationsArchive
        )
    );
END;
GO

-- Save Candidate Ranking for Audit Trail
CREATE PROCEDURE sp_SaveCandidateRanking
    @CandidateID INT,
    @JobID INT,
    @MatchScore DECIMAL(5,2)
AS
BEGIN
    INSERT INTO CandidateRankingHistory (CandidateID, JobID, MatchScore)
    VALUES (@CandidateID, @JobID, @MatchScore);
END;
GO

-- ============================================================================
-- PHASE 13: TRIGGERS
-- ============================================================================

-- Audit Application Status Changes
CREATE TRIGGER trg_Audit_ApplicationStatusChange
ON Applications
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;

    INSERT INTO AuditLog (TableName, RecordID, Operation, OldValue, NewValue, ChangedBy, ChangedAt)
    SELECT
        'Applications',
        i.ApplicationID,
        'UPDATE',
        CONCAT('StatusID: ', d.StatusID),
        CONCAT('StatusID: ', i.StatusID),
        CAST(SESSION_CONTEXT(N'UserID') AS INT),        -- FIX-03: use session context
        GETDATE()
    FROM inserted i
    JOIN deleted d ON i.ApplicationID = d.ApplicationID
    WHERE i.StatusID <> d.StatusID;
END;
GO

-- Prevent Interviewer Double-Booking
CREATE TRIGGER trg_PreventDoubleBooking
ON InterviewSchedules
INSTEAD OF INSERT
AS
BEGIN
    SET NOCOUNT ON;

    -- Check for overlapping schedules
    IF EXISTS (
        SELECT 1
        FROM inserted i
        JOIN InterviewSchedules s
          ON i.RecruiterID = s.RecruiterID
         AND i.InterviewStart < s.InterviewEnd
         AND i.InterviewEnd > s.InterviewStart
    )
    BEGIN
        RAISERROR ('Scheduling conflict: Recruiter is already booked during this time.', 16, 1);
        RETURN;
    END

    -- No conflicts, perform insert
    INSERT INTO InterviewSchedules (ApplicationID, RecruiterID, InterviewStart, InterviewEnd, CandidateConfirmed, CreatedAt)
    SELECT ApplicationID, RecruiterID, InterviewStart, InterviewEnd, CandidateConfirmed, GETDATE()
    FROM inserted;
END;
GO

-- Send Interview Email Notification
CREATE TRIGGER trg_SendInterviewEmail
ON InterviewSchedules
AFTER INSERT
AS
BEGIN
    SET NOCOUNT ON;

    INSERT INTO EmailQueue (CandidateID, EmailType, Subject, Body)
    SELECT
        c.CandidateID,
        'InterviewInvite',
        'Interview Scheduled',
        'Dear ' + c.FullName +
        ', your interview is scheduled from ' +
        CONVERT(VARCHAR, i.InterviewStart, 100) +
        ' to ' + CONVERT(VARCHAR, i.InterviewEnd, 100) + '.'
    FROM inserted i
    JOIN Applications a ON i.ApplicationID = a.ApplicationID
    JOIN Candidates c ON a.CandidateID = c.CandidateID;
END;
GO

-- Instant Auto-Reject
CREATE TRIGGER trg_InstantAutoReject
ON Applications
AFTER INSERT
AS
BEGIN
    SET NOCOUNT ON;

    UPDATE a
    SET a.StatusID = 5,
        a.RejectionReason = 'Auto-Rejected: Does not meet minimum experience requirement.'
    FROM Applications a
    JOIN inserted i ON a.ApplicationID = i.ApplicationID
    JOIN Candidates c ON a.CandidateID = c.CandidateID
    JOIN JobPostings j ON a.JobID = j.JobID
    WHERE c.YearsOfExperience < j.MinExperience
    AND a.StatusID = 1;
END;
GO

-- ============================================================================
-- PHASE 14: VIEWS & ANALYTICS
-- ============================================================================

-- Weighted Candidate Matching Score
CREATE VIEW vw_CandidateMatchScore AS
SELECT
    a.ApplicationID,
    c.CandidateID,
    c.FullName,
    j.JobID,
    j.JobTitle,
    SUM(cs.ProficiencyLevel) AS SkillScore,
    c.YearsOfExperience * 2 AS ExperienceScore,
    CASE WHEN c.Location = j.Location THEN 10 ELSE 0 END AS LocationBonus,
    SUM(cs.ProficiencyLevel) + (c.YearsOfExperience * 2) + 
    CASE WHEN c.Location = j.Location THEN 10 ELSE 0 END AS TotalMatchScore
FROM Candidates c
JOIN Applications a ON c.CandidateID = a.CandidateID
JOIN JobPostings j ON a.JobID = j.JobID
JOIN CandidateSkills cs ON c.CandidateID = cs.CandidateID
JOIN JobSkills js ON cs.SkillID = js.SkillID AND js.JobID = j.JobID
WHERE cs.ProficiencyLevel >= js.MinProficiency
  AND a.IsDeleted = 0
GROUP BY a.ApplicationID, c.CandidateID, c.FullName, c.YearsOfExperience, c.Location, j.JobID, j.JobTitle, j.Location
HAVING
    COUNT(CASE WHEN js.IsMandatory = 1 THEN 1 END) = 
    (SELECT COUNT(*) FROM JobSkills WHERE JobID = j.JobID AND IsMandatory = 1);
GO

-- Candidate Interviews
CREATE VIEW vw_CandidateInterviews AS
SELECT 
    c.UserID,
    i.ScheduleID,
    j.JobTitle,
    j.Location AS JobLocation,
    u.Username AS RecruiterName,
    i.InterviewStart,
    i.InterviewEnd,
    i.CandidateConfirmed,
    CASE 
        WHEN i.InterviewStart < GETDATE() THEN 'Past'
        ELSE 'Upcoming'
    END AS TimeStatus
FROM InterviewSchedules i
JOIN Applications a ON i.ApplicationID = a.ApplicationID
JOIN JobPostings j ON a.JobID = j.JobID
JOIN Candidates c ON a.CandidateID = c.CandidateID
JOIN Recruiters r ON i.RecruiterID = r.RecruiterID
JOIN Users u ON r.UserID = u.UserID
WHERE a.IsDeleted = 0;
GO

-- Time to Hire
CREATE VIEW vw_TimeToHire AS
SELECT
    a.ApplicationID,
    c.FullName AS CandidateName,
    j.JobTitle,
    a.AppliedDate,
    h.ChangedAt AS HiredDate,
    DATEDIFF(DAY, a.AppliedDate, h.ChangedAt) AS DaysToHire,
    'Hired' AS ApplicationStatus,
    'Direct' AS Source
FROM Applications a
JOIN Candidates c ON a.CandidateID = c.CandidateID
JOIN JobPostings j ON a.JobID = j.JobID
JOIN ApplicationStatusHistory h ON a.ApplicationID = h.ApplicationID
WHERE h.ToStatusID = (SELECT StatusID FROM ApplicationStatus WHERE StatusName = 'Hired');
GO

-- Average Time to Hire
CREATE VIEW vw_AverageTimeToHire AS
SELECT AVG(CAST(DaysToHire AS FLOAT)) AS AvgDaysToHire
FROM vw_TimeToHire;
GO

-- Hire Rate Per Job
CREATE VIEW vw_HireRatePerJob AS
SELECT
    j.JobID,
    j.JobTitle,
    COUNT(a.ApplicationID) AS TotalApplications,
    SUM(CASE WHEN s.StatusName = 'Hired' THEN 1 ELSE 0 END) AS Hires,
    CAST(SUM(CASE WHEN s.StatusName = 'Hired' THEN 1 ELSE 0 END) * 100.0 / 
         NULLIF(COUNT(a.ApplicationID), 0) AS DECIMAL(5,2)) AS HireRatePercent
FROM JobPostings j
LEFT JOIN Applications a ON j.JobID = a.JobID
LEFT JOIN ApplicationStatus s ON a.StatusID = s.StatusID
GROUP BY j.JobID, j.JobTitle;
GO

-- Recruiter Performance
CREATE VIEW vw_RecruiterPerformance AS
SELECT
    r.RecruiterID,
    u.Username AS RecruiterName,
    COUNT(DISTINCT i.ScheduleID) AS InterviewsConducted,
    SUM(CASE WHEN s.StatusName = 'Hired' THEN 1 ELSE 0 END) AS SuccessfulHires
FROM Recruiters r
JOIN Users u ON r.UserID = u.UserID
LEFT JOIN InterviewSchedules i ON r.RecruiterID = i.RecruiterID
LEFT JOIN Applications a ON i.ApplicationID = a.ApplicationID
LEFT JOIN ApplicationStatus s ON a.StatusID = s.StatusID
GROUP BY r.RecruiterID, u.Username;
GO

-- Application Funnel Analysis
CREATE VIEW vw_ApplicationFunnel AS
SELECT
    s.StatusName,
    COUNT(a.ApplicationID) AS ApplicationCount
FROM ApplicationStatus s
LEFT JOIN Applications a ON s.StatusID = a.StatusID
WHERE a.IsDeleted = 0 OR a.ApplicationID IS NULL
GROUP BY s.StatusName;
GO

-- Bias Detection: Location
CREATE VIEW vw_Bias_Location AS
SELECT
    c.Location,
    COUNT(a.ApplicationID) AS TotalApplicants,
    SUM(CASE WHEN s.StatusName = 'Hired' THEN 1 ELSE 0 END) AS HiredCount,
    CAST(SUM(CASE WHEN s.StatusName = 'Hired' THEN 1 ELSE 0 END) * 100.0 / 
         NULLIF(COUNT(a.ApplicationID), 0) AS DECIMAL(5,2)) AS HireRatePercent
FROM Applications a
JOIN Candidates c ON a.CandidateID = c.CandidateID
JOIN ApplicationStatus s ON a.StatusID = s.StatusID
WHERE a.IsDeleted = 0
GROUP BY c.Location;
GO

-- Bias Detection: Experience
CREATE VIEW vw_Bias_Experience AS
SELECT
    CASE
        WHEN c.YearsOfExperience < 2 THEN 'Junior'
        WHEN c.YearsOfExperience BETWEEN 2 AND 5 THEN 'Mid'
        ELSE 'Senior'
    END AS ExperienceGroup,
    COUNT(*) AS TotalApplicants,
    SUM(CASE WHEN s.StatusName = 'Hired' THEN 1 ELSE 0 END) AS HiredCount,
    CAST(SUM(CASE WHEN s.StatusName = 'Hired' THEN 1 ELSE 0 END) * 100.0 / 
         NULLIF(COUNT(*), 0) AS DECIMAL(5,2)) AS HireRatePercent
FROM Applications a
JOIN Candidates c ON a.CandidateID = c.CandidateID
JOIN ApplicationStatus s ON a.StatusID = s.StatusID
WHERE a.IsDeleted = 0
GROUP BY CASE
    WHEN c.YearsOfExperience < 2 THEN 'Junior'
    WHEN c.YearsOfExperience BETWEEN 2 AND 5 THEN 'Mid'
    ELSE 'Senior'
END;
GO

-- Interview Score vs Final Decision
CREATE VIEW vw_InterviewScoreVsDecision AS
SELECT
    f.ApplicationID,
    c.FullName,
    AVG((f.TechnicalScore + f.CommunicationScore + f.CultureFitScore) / 3.0) AS AvgInterviewScore,
    s.StatusName AS FinalStatus
FROM InterviewFeedback f
JOIN Applications a ON f.ApplicationID = a.ApplicationID
JOIN Candidates c ON a.CandidateID = c.CandidateID
JOIN ApplicationStatus s ON a.StatusID = s.StatusID
GROUP BY f.ApplicationID, c.FullName, s.StatusName;
GO

-- Interviewer Consistency Score
CREATE VIEW vw_InterviewerConsistency AS
SELECT
    f.InterviewerID,
    u.Username AS InterviewerName,
    COUNT(*) AS InterviewsTaken,
    AVG((f.TechnicalScore + f.CommunicationScore + f.CultureFitScore) / 3.0) AS AvgScoreGiven,
    STDEV((f.TechnicalScore + f.CommunicationScore + f.CultureFitScore) / 3.0) AS ScoreVariance
FROM InterviewFeedback f
JOIN Users u ON f.InterviewerID = u.UserID
GROUP BY f.InterviewerID, u.Username;
GO

-- Skill Gap Analysis
CREATE VIEW vw_SkillGapAnalysis AS
SELECT
    s.SkillName,
    COUNT(DISTINCT js.JobID) AS JobsRequiringSkill,
    COUNT(DISTINCT cs.CandidateID) AS CandidatesWithSkill,
    COUNT(DISTINCT js.JobID) - COUNT(DISTINCT cs.CandidateID) AS SkillGap
FROM Skills s
LEFT JOIN JobSkills js ON s.SkillID = js.SkillID
LEFT JOIN CandidateSkills cs ON s.SkillID = cs.SkillID
GROUP BY s.SkillName;
GO

-- Candidate Engagement Score
CREATE VIEW vw_CandidateEngagement AS
SELECT
    c.CandidateID,
    c.FullName,
    COUNT(i.ScheduleID) AS InterviewsScheduled,
    SUM(CASE WHEN i.CandidateConfirmed = 1 THEN 1 ELSE 0 END) AS ConfirmedInterviews,
    CAST(SUM(CASE WHEN i.CandidateConfirmed = 1 THEN 1 ELSE 0 END) * 100.0 / 
         NULLIF(COUNT(i.ScheduleID), 0) AS DECIMAL(5,2)) AS EngagementRate
FROM Candidates c
LEFT JOIN Applications a ON c.CandidateID = a.CandidateID
LEFT JOIN InterviewSchedules i ON a.ApplicationID = i.ApplicationID
GROUP BY c.CandidateID, c.FullName;
GO

-- Hiring Bottleneck Detection
CREATE VIEW vw_HiringBottlenecks AS
SELECT
    s.StatusName,
    COUNT(a.ApplicationID) AS ApplicationsInStage,
    AVG(DATEDIFF(DAY, a.AppliedDate, ISNULL(a.StatusChangedAt, GETDATE()))) AS AvgDaysInStage
FROM ApplicationStatus s
LEFT JOIN Applications a ON s.StatusID = a.StatusID
WHERE a.IsDeleted = 0 OR a.ApplicationID IS NULL
GROUP BY s.StatusName;
GO

-- Rejection Reason Analysis
CREATE VIEW vw_RejectionAnalysis AS
SELECT
    a.RejectionReason,
    COUNT(*) AS RejectionCount,
    CAST(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM Applications WHERE StatusID = 5) AS DECIMAL(5,2)) AS RejectionPercent
FROM Applications a
WHERE a.StatusID = 5
  AND a.RejectionReason IS NOT NULL
  AND a.IsDeleted = 0
GROUP BY a.RejectionReason;
GO

-- Vacancy Utilization
CREATE VIEW vw_VacancyUtilization AS
SELECT
    j.JobID,
    j.JobTitle,
    j.Description,
    j.Location,
    j.MinExperience,
    j.Vacancies,
    j.IsActive,
    j.CreatedAt,
    COUNT(a.ApplicationID) AS ApplicationCount,
    SUM(CASE WHEN s.StatusName = 'Hired' THEN 1 ELSE 0 END) AS FilledPositions
FROM JobPostings j
LEFT JOIN Applications a ON j.JobID = a.JobID AND a.IsDeleted = 0
LEFT JOIN ApplicationStatus s ON a.StatusID = s.StatusID
WHERE j.IsDeleted = 0
GROUP BY j.JobID, j.JobTitle, j.Description, j.Location, j.MinExperience, j.Vacancies, j.IsActive, j.CreatedAt;
GO

-- Silent Rejection Detector
CREATE VIEW vw_SilentRejections AS
SELECT
    a.ApplicationID,
    c.FullName,
    s.StatusName,
    DATEDIFF(DAY, a.AppliedDate, GETDATE()) AS DaysInactive,
    j.JobTitle
FROM Applications a
JOIN Candidates c ON a.CandidateID = c.CandidateID
JOIN ApplicationStatus s ON a.StatusID = s.StatusID
JOIN JobPostings j ON a.JobID = j.JobID
WHERE s.StatusName NOT IN ('Hired', 'Rejected', 'Withdrawn')
  AND DATEDIFF(DAY, a.AppliedDate, GETDATE()) > 30
  AND a.IsDeleted = 0;
GO

-- ============================================================================
-- PHASE 15: ADDITIONAL STORED PROCEDURES
-- ============================================================================

-- Schedule Interview With Recruiter
CREATE PROCEDURE sp_ScheduleInterviewWithRecruiter
    @ApplicationID INT,
    @RecruiterUserID INT,
    @StartTime DATETIME,
    @EndTime DATETIME
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @RecruiterID INT;

    SELECT @RecruiterID = RecruiterID FROM Recruiters WHERE UserID = @RecruiterUserID;

    IF @RecruiterID IS NULL
    BEGIN
        RAISERROR ('Unauthorized: User is not registered as a Recruiter.', 16, 1);
        RETURN;
    END

    INSERT INTO InterviewSchedules (ApplicationID, RecruiterID, InterviewStart, InterviewEnd)
    VALUES (@ApplicationID, @RecruiterID, @StartTime, @EndTime);
END;
GO

-- Confirm Interview
CREATE PROCEDURE sp_ConfirmInterview
    @ScheduleID INT,
    @UserID INT
AS
BEGIN
    SET NOCOUNT ON;

    IF EXISTS (
        SELECT 1 
        FROM InterviewSchedules i
        JOIN Applications a ON i.ApplicationID = a.ApplicationID
        JOIN Candidates c ON a.CandidateID = c.CandidateID
        WHERE i.ScheduleID = @ScheduleID AND c.UserID = @UserID
    )
    BEGIN
        UPDATE InterviewSchedules
        SET CandidateConfirmed = 1
        WHERE ScheduleID = @ScheduleID;

        SELECT 'Success' AS Status, 'Interview confirmed.' AS Message;
    END
    ELSE
    BEGIN
        RAISERROR('Unauthorized: This interview does not belong to your account.', 16, 1);
    END
END;
GO

