CREATE TABLE NegotiationTemplates (
    TemplateID INT IDENTITY(1,1) PRIMARY KEY,
    Scenario VARCHAR(100) NOT NULL,
    TemplateType VARCHAR(50) CHECK (TemplateType IN ('Email', 'Script', 'CounterOffer')),
