-- Feature 1: Anti-Ghosting Prediction
CREATE PROCEDURE sp_PredictGhostingRisk
    @ApplicationID INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @CandidateID INT, @RecruiterID INT, @JobID INT;
    DECLARE @CandidateScore DECIMAL(3,2), @RecruiterScore DECIMAL(3,2);
    DECLARE @ResponseTimeAvg DECIMAL(10,2), @CommunicationCount INT;
    
    SELECT @CandidateID = a.CandidateID, 
           @JobID = a.JobID,
           @RecruiterID = j.CreatedBy
    FROM Applications a
    JOIN JobPostings j ON a.JobID = j.JobID
    WHERE a.ApplicationID = @ApplicationID;
    
    SELECT @CandidateScore = ISNULL(AVG(GhostingScore), 0)
    FROM GhostingPatterns 
    WHERE UserID = @CandidateID AND UserType = 'Candidate' AND IsActive = 1;
    
    SELECT @RecruiterScore = ISNULL(AVG(GhostingScore), 0)
    FROM GhostingPatterns 
    WHERE UserID = @RecruiterID AND UserType = 'Recruiter' AND IsActive = 1;
    
    SELECT @ResponseTimeAvg = AVG(DATEDIFF(HOUR, SentAt, RespondedAt)),
           @CommunicationCount = COUNT(*)
    FROM CommunicationLogs
    WHERE ApplicationID = @ApplicationID AND RespondedAt IS NOT NULL;
    
    DECLARE @RiskScore DECIMAL(3,2);
    SET @RiskScore = (
        ISNULL(@CandidateScore, 0) * 0.4 + 
        ISNULL(@RecruiterScore, 0) * 0.3 + 
        CASE 
            WHEN @ResponseTimeAvg > 48 THEN 8.0
            WHEN @ResponseTimeAvg > 24 THEN 5.0
            WHEN @ResponseTimeAvg > 12 THEN 3.0
            ELSE 1.0 
        END * 0.2 +
        CASE 
            WHEN @CommunicationCount = 0 THEN 7.0
            WHEN @CommunicationCount < 3 THEN 4.0
            ELSE 1.0
        END * 0.1
    );
    
    SELECT 
        @RiskScore AS GhostingRiskScore,
        ISNULL(@CandidateScore, 0) AS CandidateGhostingHistory,
        ISNULL(@RecruiterScore, 0) AS RecruiterGhostingHistory,
        ISNULL(@ResponseTimeAvg, 0) AS AvgResponseTimeHours,
        ISNULL(@CommunicationCount, 0) AS TotalCommunications,
        CASE 
            WHEN @RiskScore >= 7.0 THEN 'High Risk'
            WHEN @RiskScore >= 4.0 THEN 'Medium Risk'
            ELSE 'Low Risk'
        END AS RiskLevel,
        CASE 
            WHEN @RiskScore >= 7.0 THEN 'Send escalation reminders, schedule follow-up call'
            WHEN @RiskScore >= 4.0 THEN 'Increase communication frequency'
            ELSE 'Normal monitoring'
        END AS RecommendedAction;
END;
GO

-- Feature 3: Salary Negotiation Coach
CREATE PROCEDURE sp_GenerateNegotiationStrategy
    @CandidateID INT,
    @JobID INT,
    @InitialOffer DECIMAL(10,2)
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @CandidateExp INT, @Location VARCHAR(100), @JobTitle VARCHAR(150);
    DECLARE @MarketAvg DECIMAL(10,2), @Market25 DECIMAL(10,2), @Market75 DECIMAL(10,2);
    DECLARE @CompanyRangeMin DECIMAL(10,2), @CompanyRangeMax DECIMAL(10,2);
    
    SELECT @CandidateExp = c.YearsOfExperience,
           @Location = c.Location
    FROM Candidates c
    WHERE c.CandidateID = @CandidateID;
    
    SELECT @JobTitle = j.JobTitle,
           @Location = COALESCE(@Location, j.Location)
    FROM JobPostings j
    WHERE j.JobID = @JobID;
    
    SELECT TOP 1 
        @MarketAvg = AvgSalary,
        @Market25 = Percentile25,
        @Market75 = Percentile75
    FROM SalaryBenchmarks
    WHERE JobTitle = @JobTitle
        AND Location = @Location
        AND ExperienceRange = CASE 
            WHEN @CandidateExp < 2 THEN 'Entry'
            WHEN @CandidateExp < 5 THEN 'Junior'
            WHEN @CandidateExp < 10 THEN 'Mid'
            ELSE 'Senior'
        END
    ORDER BY SampleSize DESC, LastUpdated DESC;
    
    SELECT @CompanyRangeMin = MinSalary,
           @CompanyRangeMax = MaxSalary
    FROM JobSalaryRanges
    WHERE JobID = @JobID;
    
    DECLARE @OfferPercentile DECIMAL(5,2);
    DECLARE @RecommendedCounter DECIMAL(10,2);
    DECLARE @NegotiationRoom DECIMAL(10,2);
    
    SET @OfferPercentile = CASE 
        WHEN @InitialOffer <= ISNULL(@Market25, @InitialOffer * 0.8) THEN 25
        WHEN @InitialOffer <= ISNULL(@MarketAvg, @InitialOffer * 1.0) THEN 50
        WHEN @InitialOffer <= ISNULL(@Market75, @InitialOffer * 1.2) THEN 75
        ELSE 90
    END;
    
    SET @RecommendedCounter = CASE 
        WHEN @OfferPercentile < 50 THEN ISNULL(@MarketAvg, @InitialOffer) * 1.1
        WHEN @OfferPercentile < 75 THEN ISNULL(@Market75, @InitialOffer) * 1.05
        ELSE @InitialOffer * 1.03
    END;
    
    IF @CompanyRangeMax IS NOT NULL AND @RecommendedCounter > @CompanyRangeMax
        SET @RecommendedCounter = @CompanyRangeMax * 0.95;
    
    SET @NegotiationRoom = @RecommendedCounter - @InitialOffer;
    
    SELECT 
        @InitialOffer AS InitialOffer,
        ISNULL(@MarketAvg, @InitialOffer) AS MarketAverage,
        ISNULL(@Market25, @InitialOffer * 0.8) AS Market25thPercentile,
        ISNULL(@Market75, @InitialOffer * 1.2) AS Market75thPercentile,
        @OfferPercentile AS OfferPercentile,
        @RecommendedCounter AS RecommendedCounterOffer,
        @NegotiationRoom AS NegotiationRoom,
        CASE 
            WHEN @OfferPercentile < 25 THEN 'Strongly Under Market'
            WHEN @OfferPercentile < 50 THEN 'Below Market'
            WHEN @OfferPercentile < 75 THEN 'Market Competitive'
            ELSE 'Above Market'
        END AS OfferAssessment,
        CASE 
            WHEN @OfferPercentile < 25 THEN 
                'Thank you for the offer. Based on my research of similar roles in ' + ISNULL(@Location, 'this market') + 
                ' with ' + CAST(@CandidateExp AS VARCHAR) + ' years experience, the market range is ' + 
                CAST(ISNULL(@Market25, @InitialOffer * 0.8) AS VARCHAR) + ' - ' + CAST(ISNULL(@Market75, @InitialOffer * 1.2) AS VARCHAR) + 
                '. Given my qualifications, I was expecting something closer to ' + CAST(@RecommendedCounter AS VARCHAR) + '.'
            WHEN @OfferPercentile < 50 THEN 
                'I appreciate the offer. While it''s a competitive package, market data shows similar roles at my experience level average ' + 
                CAST(ISNULL(@MarketAvg, @InitialOffer) AS VARCHAR) + '. Could we discuss reaching ' + CAST(@RecommendedCounter AS VARCHAR) + 
                ' to align with market standards?'
            WHEN @OfferPercentile < 75 THEN 
                'Thank you for the generous offer. I''m excited about the role and believe my experience could justify an increase to ' + 
                CAST(@RecommendedCounter AS VARCHAR) + '. This would put me in the top quartile for this role and reflect the value I''ll bring.'
            ELSE 
                'This is an excellent offer that I''m very excited about. While it''s already competitive, based on my unique experience, ' +
                'I believe ' + CAST(@RecommendedCounter AS VARCHAR) + ' would be appropriate.'
        END AS NegotiationScript,
        CASE 
            WHEN @NegotiationRoom > 10000 THEN 'Wait 24 hours, then counter via email'
            WHEN @NegotiationRoom > 5000 THEN 'Respond within 48 hours with counter'
            ELSE 'Accept within 72 hours or ask for minor adjustments'
        END AS TimingRecommendation,
        'Consider negotiating for: 1) Signing bonus, 2) Additional equity, 3) Early performance review, 4) Professional development budget' AS FallbackOptions;
END;
GO

-- Feature 4: Interview Optimization
CREATE PROCEDURE sp_OptimizeInterviewRounds
    @CandidateID INT,
    @JobID INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @AlreadyAssessedSkills NVARCHAR(MAX) = '';
    DECLARE @RedundantQuestionsCount INT = 0;
    DECLARE @RecommendedRounds INT = 2;
    DECLARE @SkillsToAssess NVARCHAR(MAX) = '';
    
    SELECT @AlreadyAssessedSkills = COALESCE(@AlreadyAssessedSkills + ', ', '') + s.SkillName
    FROM (
        SELECT DISTINCT s.SkillName
        FROM CandidateInterviewHistory cih
        CROSS APPLY OPENJSON(cih.QuestionsAsked) WITH (SkillID INT '$.skillId') q
        JOIN Skills s ON q.SkillID = s.SkillID
        WHERE cih.CandidateID = @CandidateID
            AND cih.InterviewDate > DATEADD(MONTH, -6, GETDATE())
    ) s;
    
    SELECT @RedundantQuestionsCount = COUNT(*)
    FROM InterviewSharedInsights isi
    WHERE isi.JobID = @JobID
        AND isi.IsRedundant = 1
        AND isi.LastAsked > DATEADD(MONTH, -1, GETDATE());
    
    SELECT @SkillsToAssess = COALESCE(@SkillsToAssess + ', ', '') + s.SkillName
    FROM (
        SELECT DISTINCT s.SkillName
        FROM JobSkills js
        JOIN Skills s ON js.SkillID = s.SkillID
        WHERE js.JobID = @JobID
            AND js.IsMandatory = 1
            AND s.SkillName NOT IN (
                SELECT value FROM STRING_SPLIT(ISNULL(@AlreadyAssessedSkills, ''), ',')
            )
    ) s;
    
    IF @SkillsToAssess = '' OR @SkillsToAssess IS NULL
        SET @RecommendedRounds = 2;
    ELSE IF (LEN(@SkillsToAssess) - LEN(REPLACE(@SkillsToAssess, ',', '')) + 1) > 5
        SET @RecommendedRounds = 3;
    ELSE
        SET @RecommendedRounds = 2;
    
    SELECT 
        @RecommendedRounds AS RecommendedInterviewRounds,
        ISNULL(@AlreadyAssessedSkills, 'None') AS AlreadyAssessedSkills,
        ISNULL(@SkillsToAssess, 'All skills need assessment') AS SkillsToAssess,
        ISNULL(@RedundantQuestionsCount, 0) AS RedundantQuestionsDetected,
        CASE 
            WHEN @RedundantQuestionsCount > 3 THEN 'High redundancy detected. Consider question rotation.'
            ELSE 'Question redundancy at acceptable levels.'
        END AS RedundancyAssessment,
        CASE @RecommendedRounds
            WHEN 2 THEN 'Round 1: Technical assessment | Round 2: Behavioral & Culture fit'
            WHEN 3 THEN 'Round 1: Screening | Round 2: Technical deep dive | Round 3: Leadership & Culture'
            ELSE 'Custom structure based on skills gap'
        END AS SuggestedStructure,
        (@RecommendedRounds * 60) AS EstimatedMinutes,
        (4 * 60) - (@RecommendedRounds * 60) AS TimeSavedMinutes;
END;
GO

-- Feature 5: Remote Compatibility Analysis
CREATE PROCEDURE sp_AnalyzeRemoteCompatibility
    @CandidateID INT,
    @JobID INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @CandidateScore DECIMAL(3,2), @CompanyScore INT;
    DECLARE @TimezoneOverlap DECIMAL(4,2), @OptimalOverlap DECIMAL(4,2);
    DECLARE @CandidateLocation VARCHAR(100), @CompanyLocation VARCHAR(100);
    DECLARE @WorkspaceQuality INT, @SelfMotivation INT;
    
    SELECT @CandidateScore = rc.OverallRemoteScore,
           @WorkspaceQuality = rc.WorkspaceQuality,
           @SelfMotivation = rc.SelfMotivationScore,
           @CandidateLocation = c.Location
    FROM RemoteCompatibility rc
    JOIN Candidates c ON rc.CandidateID = c.CandidateID
    WHERE rc.CandidateID = @CandidateID;
    
    SELECT @CompanyLocation = j.Location
    FROM JobPostings j
    WHERE j.JobID = @JobID;
    
    SELECT @CompanyScore = crp.RemoteOnboardingScore
    FROM CompanyRemotePolicy crp
    JOIN JobPostings j ON crp.RecruiterID = j.CreatedBy
    WHERE j.JobID = @JobID;
    
    SET @TimezoneOverlap = CASE 
        WHEN @CandidateLocation = @CompanyLocation THEN 8.0
        WHEN @CandidateLocation LIKE '%Dhaka%' AND @CompanyLocation LIKE '%Dhaka%' THEN 8.0
        WHEN @CandidateLocation LIKE '%Chittagong%' AND @CompanyLocation LIKE '%Dhaka%' THEN 8.0
        ELSE 2.0
    END;
    
    SET @OptimalOverlap = 4.0;
    
    DECLARE @CompatibilityScore DECIMAL(5,2);
    SET @CompatibilityScore = (
        ISNULL(@CandidateScore, 5.0) * 0.4 +
        ISNULL(@CompanyScore, 5.0) * 0.3 +
        CASE 
            WHEN @TimezoneOverlap >= @OptimalOverlap THEN 9.0
            WHEN @TimezoneOverlap >= @OptimalOverlap * 0.5 THEN 6.0
            ELSE 3.0
        END * 0.2 +
        CASE 
            WHEN @WorkspaceQuality >= 4 THEN 8.0
            WHEN @WorkspaceQuality >= 3 THEN 5.0
            ELSE 2.0
        END * 0.1
    );
    
    SELECT 
        @CompatibilityScore AS RemoteCompatibilityScore,
        ISNULL(@CandidateScore, 5.0) AS CandidateRemoteReadiness,
        ISNULL(@CompanyScore, 5.0) AS CompanyRemoteMaturity,
        @TimezoneOverlap AS TimezoneOverlapHours,
        @OptimalOverlap AS OptimalOverlapHours,
        ISNULL(@WorkspaceQuality, 3) AS WorkspaceQualityScore,
        ISNULL(@SelfMotivation, 5) AS SelfMotivationScore,
        CASE 
            WHEN @CompatibilityScore >= 7.5 THEN 'Excellent remote fit'
            WHEN @CompatibilityScore >= 6.0 THEN 'Good remote fit'
            WHEN @CompatibilityScore >= 4.5 THEN 'Moderate remote fit'
            ELSE 'Poor remote fit - needs support'
        END AS CompatibilityAssessment,
        CASE 
            WHEN @TimezoneOverlap < @OptimalOverlap THEN 'Consider flexible hours or async work arrangements'
            WHEN @WorkspaceQuality < 3 THEN 'Recommend home office stipend or co-working space'
            WHEN @CompanyScore IS NULL OR @CompanyScore < 5 THEN 'Company may need to improve remote onboarding'
            ELSE 'No major concerns detected'
        END AS Recommendations,
        CASE 
            WHEN @CompatibilityScore >= 7.5 THEN 'High probability of remote success (>80%)'
            WHEN @CompatibilityScore >= 6.0 THEN 'Good probability of remote success (60-80%)'
            WHEN @CompatibilityScore >= 4.5 THEN 'Moderate probability (40-60%)'
            ELSE 'High risk of remote failure (<40%)'
        END AS SuccessPrediction;
END;
GO

-- Feature 7: Career Path Prediction
CREATE PROCEDURE sp_PredictCareerPath
    @CandidateID INT,
    @TargetRole VARCHAR(150),
    @Years INT = 5
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @CurrentRole VARCHAR(150), @CurrentSkills NVARCHAR(MAX);
    DECLARE @CurrentExp INT, @EducationLevel VARCHAR(50);
    DECLARE @PathProbability DECIMAL(3,2), @TransitionMonths INT;
    DECLARE @SkillsGap NVARCHAR(MAX), @SalaryIncrease DECIMAL(5,2);
    
    SELECT @CurrentExp = c.YearsOfExperience,
           @EducationLevel = ISNULL(dm.EducationLevel, 'Not Specified'),
           @CurrentRole = (
               SELECT TOP 1 JobTitle 
               FROM Applications a 
               JOIN JobPostings j ON a.JobID = j.JobID 
               WHERE a.CandidateID = @CandidateID 
               ORDER BY a.AppliedDate DESC
           )
    FROM Candidates c
    LEFT JOIN DiversityMetrics dm ON dm.ApplicationID IN (
        SELECT TOP 1 ApplicationID FROM Applications WHERE CandidateID = @CandidateID ORDER BY AppliedDate DESC
    )
    WHERE c.CandidateID = @CandidateID;
    
    SELECT @CurrentSkills = COALESCE(@CurrentSkills + ', ', '') + s.SkillName
    FROM CandidateSkills cs
    JOIN Skills s ON cs.SkillID = s.SkillID
    WHERE cs.CandidateID = @CandidateID;
    
    SELECT TOP 1 
        @PathProbability = cp.Probability,
        @TransitionMonths = cp.AvgTransitionMonths,
        @SkillsGap = cp.RequiredSkillsGap,
        @SalaryIncrease = cp.SalaryIncreaseAvg
    FROM CareerPaths cp
    WHERE cp.FromRole LIKE '%' + ISNULL(@CurrentRole, 'Software Engineer') + '%'
        AND cp.ToRole LIKE '%' + @TargetRole + '%'
    ORDER BY cp.Probability DESC, cp.SampleSize DESC;
    
    DECLARE @AdjustedProbability DECIMAL(3,2);
    SET @AdjustedProbability = ISNULL(@PathProbability, 0.5);
    
    IF @CurrentExp >= 10 SET @AdjustedProbability = @AdjustedProbability * 1.2;
    ELSE IF @CurrentExp >= 5 SET @AdjustedProbability = @AdjustedProbability * 1.1;
    ELSE IF @CurrentExp >= 2 SET @AdjustedProbability = @AdjustedProbability * 0.9;
    ELSE SET @AdjustedProbability = @AdjustedProbability * 0.7;
    
    IF @AdjustedProbability > 0.95 SET @AdjustedProbability = 0.95;
    
    DECLARE @TimelineMonths INT;
    SET @TimelineMonths = ISNULL(@TransitionMonths, 36);
    
    IF @Years * 12 < @TimelineMonths 
        SET @TimelineMonths = @Years * 12;
    
    DECLARE @DevelopmentPlan NVARCHAR(MAX);
    SET @DevelopmentPlan = 'Based on your current skills in ' + ISNULL(@CurrentSkills, 'general programming') + 
        ', you need to develop: ' + ISNULL(@SkillsGap, 'advanced skills in your target domain') + 
        '. Recommended learning path: 1) Online courses (3-6 months), 2) Practical projects (6-12 months), 3) Mentorship.';
    
    SELECT 
        ISNULL(@CurrentRole, 'Not specified') AS CurrentRole,
        @TargetRole AS TargetRole,
        @AdjustedProbability AS SuccessProbability,
        @TimelineMonths AS EstimatedTimelineMonths,
        ISNULL(@SalaryIncrease, 30.0) AS ExpectedSalaryIncreasePercent,
        ISNULL(@CurrentExp, 0) AS YearsOfExperience,
        ISNULL(@EducationLevel, 'Not specified') AS EducationLevel,
        CASE 
            WHEN @AdjustedProbability >= 0.8 THEN 'Highly achievable'
            WHEN @AdjustedProbability >= 0.6 THEN 'Achievable with effort'
            WHEN @AdjustedProbability >= 0.4 THEN 'Challenging but possible'
            ELSE 'Very difficult - consider alternative paths'
        END AS FeasibilityAssessment,
        @DevelopmentPlan AS DevelopmentPlan,
        (
            SELECT TOP 3 
                cp.ToRole AS AlternativeRole,
                cp.Probability,
                cp.AvgTransitionMonths AS TimelineMonths
            FROM CareerPaths cp
            WHERE cp.FromRole LIKE '%' + ISNULL(@CurrentRole, 'Software Engineer') + '%'
                AND cp.ToRole <> @TargetRole
                AND cp.Probability >= 0.6
            ORDER BY cp.Probability DESC
            FOR JSON PATH
        ) AS AlternativePaths;
END;
GO

-- Feature 8: Onboarding Success Prediction
CREATE PROCEDURE sp_PredictOnboardingSuccess
    @CandidateID INT,
    @JobID INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @RemoteScore DECIMAL(3,2), @SocialSkills INT;
    DECLARE @PreviousRemoteMonths INT, @CareerGaps INT;
    DECLARE @CompanyOnboardingScore INT;
    DECLARE @SimilarSuccessRate DECIMAL(5,2);
    
    SELECT @RemoteScore = rc.OverallRemoteScore,
           @PreviousRemoteMonths = rc.PreviousRemoteExperienceMonths,
           @SocialSkills = osf.SocialIntegrationScore
    FROM RemoteCompatibility rc
    LEFT JOIN OnboardingSuccessFactors osf ON osf.HiredCandidateID = rc.CandidateID
    WHERE rc.CandidateID = @CandidateID;
    
    SELECT @CareerGaps = ISNULL(dm.CareerGapMonths, 0)
    FROM DiversityMetrics dm
    WHERE dm.ApplicationID IN (
        SELECT ApplicationID FROM Applications 
        WHERE CandidateID = @CandidateID AND JobID = @JobID
    );
    
    SELECT @CompanyOnboardingScore = crp.RemoteOnboardingScore
    FROM CompanyRemotePolicy crp
    JOIN JobPostings j ON crp.RecruiterID = j.CreatedBy
    WHERE j.JobID = @JobID;
    
    SELECT @SimilarSuccessRate = AVG(
        CASE osf.SuccessCategory
            WHEN 'High' THEN 0.9
            WHEN 'Medium' THEN 0.7
            WHEN 'Low' THEN 0.4
            ELSE 0.5
        END
    )
    FROM OnboardingSuccessFactors osf
    JOIN Applications a ON osf.HiredCandidateID = a.CandidateID
    WHERE a.JobID = @JobID
        AND osf.HiredCandidateID <> @CandidateID;
    
    DECLARE @SuccessProbability DECIMAL(5,2);
    SET @SuccessProbability = 0.5;
    
    IF @RemoteScore IS NOT NULL
        SET @SuccessProbability = @SuccessProbability + (@RemoteScore / 10 * 0.2);
    
    IF @CompanyOnboardingScore IS NOT NULL
        SET @SuccessProbability = @SuccessProbability + (@CompanyOnboardingScore / 10 * 0.2);
    
    IF @SimilarSuccessRate IS NOT NULL
        SET @SuccessProbability = @SuccessProbability + (@SimilarSuccessRate * 0.3);
    
    IF @CareerGaps > 12 
        SET @SuccessProbability = @SuccessProbability * 0.8;
    
    IF @PreviousRemoteMonths = 0 
        SET @SuccessProbability = @SuccessProbability * 0.9;
    
    IF @SocialSkills < 5 
        SET @SuccessProbability = @SuccessProbability * 0.85;
    
    IF @SuccessProbability > 0.95 SET @SuccessProbability = 0.95;
    IF @SuccessProbability < 0.1 SET @SuccessProbability = 0.1;
    
    DECLARE @RiskFactors NVARCHAR(MAX);
    SET @RiskFactors = '';
    
    IF @CareerGaps > 12 
        SET @RiskFactors = @RiskFactors + 'Significant career gap (' + CAST(@CareerGaps AS VARCHAR) + ' months). ';
    
    IF @PreviousRemoteMonths = 0 
        SET @RiskFactors = @RiskFactors + 'No previous remote work experience. ';
    
    IF @SocialSkills < 5 
        SET @RiskFactors = @RiskFactors + 'Below average social integration score. ';
    
    IF @CompanyOnboardingScore IS NULL OR @CompanyOnboardingScore < 5
        SET @RiskFactors = @RiskFactors + 'Company remote onboarding may need improvement. ';
    
    DECLARE @Recommendations NVARCHAR(MAX);
    SET @Recommendations = CASE 
        WHEN @SuccessProbability < 0.6 THEN 
            'High-risk onboarding. Recommendations: 1) Assign dedicated mentor, 2) 30-60-90 day plan, 3) Weekly check-ins, 4) Early performance indicators'
        WHEN @SuccessProbability < 0.8 THEN 
            'Moderate risk. Recommendations: 1) Bi-weekly mentor meetings, 2) Clear first project, 3) Social integration activities'
        ELSE 
            'Low risk. Standard onboarding process should be sufficient.'
    END;
    
    SELECT 
        @SuccessProbability AS SuccessProbability,
        @RiskFactors AS RiskFactors,
        @Recommendations AS Recommendations,
        CASE 
            WHEN @SuccessProbability >= 0.8 THEN 'Low Risk'
            WHEN @SuccessProbability >= 0.6 THEN 'Medium Risk'
            ELSE 'High Risk'
        END AS RiskLevel,
        CASE 
            WHEN @SuccessProbability >= 0.8 THEN 24
            WHEN @SuccessProbability >= 0.6 THEN 18
            WHEN @SuccessProbability >= 0.4 THEN 12
            ELSE 6
        END AS PredictedRetentionMonths;
END;
GO

-- Feature 9: Referral Intelligence
CREATE PROCEDURE sp_SuggestReferrals
    @JobID INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @RequiredSkills NVARCHAR(MAX);
    DECLARE @Location VARCHAR(100);
    DECLARE @MinExperience INT;
    
    SELECT @Location = j.Location,
           @MinExperience = j.MinExperience
    FROM JobPostings j
    WHERE j.JobID = @JobID;
    
    SELECT @RequiredSkills = STRING_AGG(s.SkillName, ',')
    FROM JobSkills js
    JOIN Skills s ON js.SkillID = s.SkillID
    WHERE js.JobID = @JobID AND js.IsMandatory = 1;
    
    WITH PotentialReferrers AS (
        SELECT 
            c.CandidateID,
            c.FullName,
            c.YearsOfExperience,
            c.Location,
            (
                SELECT COUNT(*) 
                FROM NetworkStrength ns 
                WHERE ns.CandidateID = c.CandidateID 
                AND ns.ConnectionStrength >= 7
            ) AS StrongConnectionsCount,
            ISNULL(rp.ConversionRate, 0) AS HistoricalConversionRate,
            (
                SELECT COUNT(*) 
                FROM CandidateSkills cs
                JOIN JobSkills js ON cs.SkillID = js.SkillID
                WHERE cs.CandidateID = c.CandidateID
                AND js.JobID = @JobID
                AND js.IsMandatory = 1
            ) * 100.0 / NULLIF((
                SELECT COUNT(*) 
                FROM JobSkills 
                WHERE JobID = @JobID AND IsMandatory = 1
            ), 0) AS SkillsMatchPercent
        FROM Candidates c
        LEFT JOIN ReferralPerformance rp ON rp.ReferrerID = c.CandidateID
        WHERE c.YearsOfExperience >= @MinExperience * 0.8
    ),
    NetworkAnalysis AS (
        SELECT 
            pr.CandidateID AS ReferrerID,
            pr.FullName AS ReferrerName,
            pr.HistoricalConversionRate,
            pr.SkillsMatchPercent,
            (
                SELECT TOP 5
                    c2.CandidateID,
                    c2.FullName,
                    c2.YearsOfExperience,
                    c2.Location,
                    ns.ConnectionStrength,
                    ns.TrustLevel,
                    (
                        SELECT COUNT(*) 
                        FROM CandidateSkills cs
                        JOIN JobSkills js ON cs.SkillID = js.SkillID
                        WHERE cs.CandidateID = c2.CandidateID
                        AND js.JobID = @JobID
                        AND js.IsMandatory = 1
                    ) AS MatchingSkillsCount,
                    (
                        CASE WHEN c2.YearsOfExperience >= @MinExperience THEN 20 ELSE 10 END +
                        CASE WHEN c2.Location = @Location THEN 15 ELSE 5 END +
                        ns.ConnectionStrength * 5 +
                        ns.TrustLevel * 4 +
                        (
                            SELECT COUNT(*) 
                            FROM CandidateSkills cs
                            JOIN JobSkills js ON cs.SkillID = js.SkillID
                            WHERE cs.CandidateID = c2.CandidateID
                            AND js.JobID = @JobID
                            AND js.IsMandatory = 1
                        ) * 10
                    ) AS FitScore
                FROM NetworkStrength ns
                JOIN Candidates c2 ON ns.ConnectionID = c2.CandidateID
                WHERE ns.CandidateID = pr.CandidateID
                    AND c2.CandidateID NOT IN (
                        SELECT CandidateID FROM Applications WHERE JobID = @JobID
                    )
                    AND ns.ConnectionStrength >= 5
                ORDER BY FitScore DESC
                FOR JSON PATH
            ) AS PotentialReferrals
        FROM PotentialReferrers pr
        WHERE pr.StrongConnectionsCount >= 3
            AND pr.SkillsMatchPercent >= 50
    )
    SELECT 
        ReferrerID,
        ReferrerName,
        HistoricalConversionRate,
        SkillsMatchPercent,
        PotentialReferrals,
        (HistoricalConversionRate * 0.6 + SkillsMatchPercent * 0.4) AS ReferrerQualityScore,
        CASE 
            WHEN HistoricalConversionRate >= 70 THEN 'High (>70%)'
            WHEN HistoricalConversionRate >= 50 THEN 'Medium (50-70%)'
            WHEN HistoricalConversionRate >= 30 THEN 'Low (30-50%)'
            ELSE 'Very Low (<30%)'
        END AS EstimatedSuccessProbability
    FROM NetworkAnalysis
    WHERE PotentialReferrals IS NOT NULL
    ORDER BY ReferrerQualityScore DESC;
END;
GO

-- sp_GenerateMarketAlerts: FIX-09 — replaced #temp table with @table variable
CREATE PROCEDURE sp_GenerateMarketAlerts
    @RecruiterID INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @RecruiterLocation VARCHAR(100);
    DECLARE @RelevantSkills TABLE (SkillName VARCHAR(100) PRIMARY KEY);

    SELECT @RecruiterLocation = r.Department FROM Recruiters r WHERE r.RecruiterID = @RecruiterID;

    INSERT INTO @RelevantSkills (SkillName)
    SELECT DISTINCT s.SkillName
    FROM JobPostings  j
    JOIN JobSkills    js ON j.JobID  = js.JobID
    JOIN Skills       s  ON js.SkillID = s.SkillID
    WHERE j.CreatedBy  = @RecruiterID
      AND j.IsActive   = 1
      AND j.IsDeleted  = 0;

    -- FIX-09: Table variable instead of #temp table (parallelism-safe)
    DECLARE @Alerts TABLE (
        AlertType       VARCHAR(50),
        SkillID         INT          NULL,
        SkillName       VARCHAR(200),
        Location        VARCHAR(100),
        DemandScore     INT          NULL,
        SupplyScore     INT          NULL,
        ImbalanceScore  INT          NULL,
        SalaryTrend     VARCHAR(20)  NULL,
        AvgSalary       DECIMAL(10,2) NULL,
        Description     NVARCHAR(MAX),
        Severity        INT,
        TriggeredAt     DATETIME     DEFAULT GETDATE(),
        ExpiresAt       DATETIME
    );

    INSERT INTO @Alerts (AlertType, SkillID, SkillName, Location, DemandScore, SupplyScore,
                         ImbalanceScore, SalaryTrend, AvgSalary, Description, Severity, ExpiresAt)
    SELECT
        CASE WHEN mi.SalaryTrend IN ('Rising','Falling') THEN 'Salary Alert' ELSE 'Demand Alert' END,
        mi.SkillID, s.SkillName, mi.Location, mi.DemandScore, mi.SupplyScore,
        mi.DemandScore - mi.SupplyScore, mi.SalaryTrend, mi.AvgSalary,
        CONCAT('Alert for ', s.SkillName, ' in ', mi.Location, ': Trend is ', mi.SalaryTrend,
               '. Avg: ', FORMAT(mi.AvgSalary,'N2'), '. Imbalance: ', (mi.DemandScore - mi.SupplyScore)),
        CASE
            WHEN (mi.DemandScore - mi.SupplyScore) > 30 THEN 5
            WHEN (mi.DemandScore - mi.SupplyScore) > 15 THEN 3
            ELSE 2
        END,
        DATEADD(DAY, 30, GETDATE())
    FROM MarketIntelligence mi
    JOIN Skills s ON mi.SkillID = s.SkillID
    JOIN @RelevantSkills rs ON s.SkillName = rs.SkillName
    WHERE mi.Location   = @RecruiterLocation
      AND mi.LastUpdated > DATEADD(DAY, -14, GETDATE());

    INSERT INTO @Alerts (AlertType, SkillName, Location, AvgSalary, Description, Severity, ExpiresAt)
    SELECT
        'Competitor Alert', ca.JobTitle, ca.Location, ca.ListedSalary,
        CONCAT('Competitor ', ca.CompetitorName, ' hiring for ', ca.JobTitle,
               ' at ', FORMAT(ca.ListedSalary,'N2')),
        3, DATEADD(DAY, 60, GETDATE())
    FROM CompetitorAnalysis ca
    WHERE ca.Location    = @RecruiterLocation
      AND ca.AnalysisDate > DATEADD(DAY, -30, GETDATE())
      AND EXISTS (
          SELECT 1 FROM JobPostings jp
          WHERE jp.CreatedBy = @RecruiterID
            AND ca.JobTitle LIKE '%' + jp.JobTitle + '%'
      );

    SELECT * FROM @Alerts ORDER BY Severity DESC, TriggeredAt DESC;
END;
GO

-- ============================================================================
-- PHASE 18: INNOVATIVE FEATURES VIEWS
-- ============================================================================

-- View for Ghosting Risk Dashboard
CREATE VIEW vw_GhostingRiskDashboard AS
SELECT 
    a.ApplicationID,
    a.CandidateID,
    c.FullName AS CandidateName,
    j.JobTitle,
    u.Username AS RecruiterName,
    ISNULL(gp_c.GhostingScore, 0) AS CandidateGhostingScore,
    ISNULL(gp_r.GhostingScore, 0) AS RecruiterGhostingScore,
    (ISNULL(gp_c.GhostingScore, 0) + ISNULL(gp_r.GhostingScore, 0)) / 2.0 AS OverallRiskScore,
    ISNULL(cl.AvgResponseTime, 0) AS AvgResponseTime,
    ISNULL(cl.TotalCommunications, 0) AS TotalCommunications,
    CASE 
        WHEN ISNULL(gp_c.GhostingScore, 0) >= 7 OR ISNULL(gp_r.GhostingScore, 0) >= 7 THEN 'High'
        WHEN ISNULL(gp_c.GhostingScore, 0) >= 5 OR ISNULL(gp_r.GhostingScore, 0) >= 5 THEN 'Medium'
        ELSE 'Low'
    END AS OverallRiskLevel,
    a.StatusID,
    s.StatusName,
    DATEDIFF(DAY, a.AppliedDate, GETDATE()) AS DaysSinceApplication
FROM Applications a
JOIN Candidates c ON a.CandidateID = c.CandidateID
JOIN JobPostings j ON a.JobID = j.JobID
JOIN Users u ON j.CreatedBy = u.UserID
JOIN ApplicationStatus s ON a.StatusID = s.StatusID
LEFT JOIN (
    SELECT UserID, AVG(GhostingScore) AS GhostingScore
    FROM GhostingPatterns 
    WHERE UserType = 'Candidate'
    GROUP BY UserID
) gp_c ON c.UserID = gp_c.UserID
LEFT JOIN (
    SELECT UserID, AVG(GhostingScore) AS GhostingScore
    FROM GhostingPatterns 
    WHERE UserType = 'Recruiter'
    GROUP BY UserID
) gp_r ON j.CreatedBy = gp_r.UserID
LEFT JOIN (
    SELECT 
        ApplicationID,
        AVG(DATEDIFF(HOUR, SentAt, RespondedAt)) AS AvgResponseTime,
        COUNT(*) AS TotalCommunications
    FROM CommunicationLogs
    WHERE RespondedAt IS NOT NULL
    GROUP BY ApplicationID
) cl ON a.ApplicationID = cl.ApplicationID
WHERE a.IsDeleted = 0;
GO

-- View for Salary Transparency
CREATE VIEW vw_SalaryTransparency AS
SELECT 
    j.JobID,
    j.JobTitle,
    j.Location,
    j.MinExperience,
    jsr.MinSalary,
    jsr.MaxSalary,
    jsr.Currency,
    jsr.IsTransparent,
    sb.AvgSalary AS MarketAverage,
    sb.Percentile25 AS Market25th,
    sb.Percentile75 AS Market75th,
    CASE 
        WHEN jsr.MinSalary IS NULL THEN 'Not Disclosed'
        WHEN jsr.MaxSalary IS NULL THEN 'Range Not Complete'
        WHEN jsr.IsTransparent = 1 THEN 'Fully Transparent'
        ELSE 'Partially Transparent'
    END AS TransparencyLevel,
    CAST(COUNT(a.ApplicationID) AS DECIMAL) / NULLIF(j.Vacancies, 0) AS ApplicationsPerVacancy,
    AVG(DATEDIFF(DAY, a.AppliedDate, GETDATE())) AS AvgDaysOpen
FROM JobPostings j
LEFT JOIN JobSalaryRanges jsr ON j.JobID = jsr.JobID
LEFT JOIN SalaryBenchmarks sb ON sb.JobTitle = j.JobTitle 
    AND sb.Location = j.Location
    AND sb.ExperienceRange = CASE 
        WHEN j.MinExperience < 2 THEN 'Entry'
        WHEN j.MinExperience < 5 THEN 'Junior'
        WHEN j.MinExperience < 10 THEN 'Mid'
        ELSE 'Senior'
    END
LEFT JOIN Applications a ON j.JobID = a.JobID AND a.IsDeleted = 0
WHERE j.IsActive = 1 AND j.IsDeleted = 0
GROUP BY j.JobID, j.JobTitle, j.Location, j.MinExperience, j.Vacancies,
         jsr.MinSalary, jsr.MaxSalary, jsr.Currency, jsr.IsTransparent,
         sb.AvgSalary, sb.Percentile25, sb.Percentile75;
GO

-- View for Skill Verification Status
CREATE VIEW vw_SkillVerificationStatus AS
SELECT 
    c.CandidateID,
    c.FullName,
    s.SkillName,
    cs.ProficiencyLevel AS ClaimedLevel,
    sv.VerificationScore,
    sv.VerificationMethod,
    sv.VerifiedAt,
    sv.ExpiryDate,
    sv.ConfidenceLevel,
    CASE 
        WHEN sv.VerificationScore >= 80 THEN 'Verified (High)'
        WHEN sv.VerificationScore >= 60 THEN 'Verified (Medium)'
        WHEN sv.VerificationScore IS NULL THEN 'Not Verified'
        ELSE 'Verification Failed'
    END AS VerificationStatus,
    DATEDIFF(MONTH, sv.VerifiedAt, GETDATE()) AS MonthsSinceVerification,
    CASE 
        WHEN sv.ExpiryDate IS NULL OR sv.ExpiryDate > GETDATE() THEN 'Valid'
        ELSE 'Expired'
    END AS ValidityStatus
FROM Candidates c
JOIN CandidateSkills cs ON c.CandidateID = cs.CandidateID
JOIN Skills s ON cs.SkillID = s.SkillID
LEFT JOIN SkillVerifications sv ON c.CandidateID = sv.CandidateID 
    AND cs.SkillID = sv.SkillID;
GO

-- View for Diversity Analytics Funnel
CREATE VIEW vw_DiversityAnalyticsFunnel AS
SELECT 
    dm.Gender,
    dm.Ethnicity,
    dm.EducationLevel,
    dm.CareerGapMonths,
    COUNT(DISTINCT a.ApplicationID) AS TotalApplications,
    SUM(CASE WHEN a.StatusID >= 2 THEN 1 ELSE 0 END) AS Screened,
    SUM(CASE WHEN a.StatusID >= 3 THEN 1 ELSE 0 END) AS Interviewed,
    SUM(CASE WHEN a.StatusID = 4 THEN 1 ELSE 0 END) AS Hired,
    SUM(CASE WHEN a.StatusID = 5 THEN 1 ELSE 0 END) AS Rejected,
    CAST(SUM(CASE WHEN a.StatusID = 4 THEN 1 ELSE 0 END) * 100.0 / 
         NULLIF(COUNT(DISTINCT a.ApplicationID), 0) AS DECIMAL(5,2)) AS HireRate,
    AVG(DATEDIFF(DAY, a.AppliedDate, 
        CASE WHEN a.StatusID = 4 THEN a.StatusChangedAt ELSE GETDATE() END)) AS AvgDaysInProcess
FROM DiversityMetrics dm
JOIN Applications a ON dm.ApplicationID = a.ApplicationID
WHERE dm.AnonymizedHash IS NOT NULL
    AND a.IsDeleted = 0
GROUP BY dm.Gender, dm.Ethnicity, dm.EducationLevel, dm.CareerGapMonths
HAVING COUNT(DISTINCT a.ApplicationID) >= 3;
GO

-- View for Remote Compatibility Matrix
CREATE VIEW vw_RemoteCompatibilityMatrix AS
SELECT 
    c.CandidateID,
    c.FullName,
    c.Location AS CandidateLocation,
    rc.OverallRemoteScore,
    rc.WorkspaceQuality,
    rc.TimezoneAlignment,
    rc.CommunicationPreference,
    rc.DistractionResistance,
    rc.SelfMotivationScore,
    rc.PreviousRemoteExperienceMonths,
    j.JobID,
    j.JobTitle,
    j.Location AS JobLocation,
    crp.RemoteOnboardingScore AS CompanyRemoteScore,
    crp.AsyncWorkPercentage,
    crp.MeetingCulture,
    crp.TechProvided,
    toa.OverlapHours,
    toa.OverlapScore,
    CASE 
        WHEN rc.OverallRemoteScore >= 8 AND crp.RemoteOnboardingScore >= 7 THEN 'Excellent Match'
        WHEN rc.OverallRemoteScore >= 6 AND crp.RemoteOnboardingScore >= 5 THEN 'Good Match'
        WHEN rc.OverallRemoteScore >= 4 AND crp.RemoteOnboardingScore >= 3 THEN 'Moderate Match'
        ELSE 'Poor Match'
    END AS CompatibilityAssessment
FROM Candidates c
JOIN RemoteCompatibility rc ON c.CandidateID = rc.CandidateID
JOIN Applications a ON c.CandidateID = a.CandidateID  -- FIX-08: scope to applications only
JOIN JobPostings j ON a.JobID = j.JobID
LEFT JOIN CompanyRemotePolicy crp ON j.CreatedBy = crp.RecruiterID
LEFT JOIN TimezoneOverlapAnalysis toa ON c.CandidateID = toa.CandidateID 
    AND j.JobID = toa.JobID
WHERE j.IsActive = 1 AND j.IsDeleted = 0
    AND rc.OverallRemoteScore IS NOT NULL;
GO

-- View for Career Path Insights
CREATE VIEW vw_CareerPathInsights AS
SELECT 
    c.CandidateID,
    c.FullName,
    c.YearsOfExperience,
    cg.TargetRole,
    cg.CurrentReadinessScore,
    cg.ProgressPercentage,
    cp.FromRole AS CurrentRoleArchetype,
    cp.ToRole AS TargetRoleArchetype,
    cp.Probability AS TransitionProbability,
    cp.AvgTransitionMonths,
    cp.SalaryIncreaseAvg,
    cp.FutureProofScore,
    (
        SELECT STRING_AGG(s.SkillName, ', ') 
        FROM (
            SELECT TOP 5 s.SkillName
            FROM CandidateSkills cs
            JOIN Skills s ON cs.SkillID = s.SkillID
            WHERE cs.CandidateID = c.CandidateID
            ORDER BY cs.ProficiencyLevel DESC
        ) s
    ) AS TopSkills,
    (
        SELECT COUNT(*) 
        FROM LearningResources lr
        WHERE lr.SkillID IN (
            SELECT SkillID FROM CandidateSkills WHERE CandidateID = c.CandidateID
        )
        AND lr.IsActive = 1
    ) AS AvailableLearningResources
FROM Candidates c
LEFT JOIN CandidateCareerGoals cg ON c.CandidateID = cg.CandidateID AND cg.IsActive = 1
LEFT JOIN CareerPaths cp ON cp.FromRole LIKE '%' + ISNULL((
    SELECT TOP 1 JobTitle 
    FROM Applications a 
    JOIN JobPostings j ON a.JobID = j.JobID 
    WHERE a.CandidateID = c.CandidateID 
    ORDER BY a.AppliedDate DESC
), '') + '%'
    AND cp.ToRole LIKE '%' + ISNULL(cg.TargetRole, '') + '%'
WHERE c.CandidateID IS NOT NULL
GROUP BY c.CandidateID, c.FullName, c.YearsOfExperience, cg.TargetRole, 
         cg.CurrentReadinessScore, cg.ProgressPercentage,
         cp.FromRole, cp.ToRole, cp.Probability, cp.AvgTransitionMonths,
         cp.SalaryIncreaseAvg, cp.FutureProofScore;
GO

-- View for Referral Intelligence
CREATE VIEW vw_ReferralIntelligence AS
SELECT 
    r.ReferrerID,
    c1.FullName AS ReferrerName,
    r.ReferredCandidateID,
    c2.FullName AS ReferredCandidateName,
    r.JobID,
    j.JobTitle,
    r.ReferralStrength,
    r.RelationshipType,
    r.ReferralDate,
    r.BonusAmount,
    r.HireResult,
    r.QualityScore,
    ns.ConnectionStrength,
    ns.TrustLevel,
    ns.LastInteraction,
    rp.ConversionRate AS ReferrerHistoricalRate,
    rp.TotalReferrals,
    rp.SuccessfulReferrals,
    CASE 
        WHEN r.HireResult = 1 THEN 'Successful'
        WHEN r.HireResult = 0 THEN 'Unsuccessful'
        ELSE 'Pending'
    END AS ReferralOutcome,
    DATEDIFF(DAY, r.ReferralDate, GETDATE()) AS DaysSinceReferral
FROM ReferralNetwork r
JOIN Candidates c1 ON r.ReferrerID = c1.CandidateID
JOIN Candidates c2 ON r.ReferredCandidateID = c2.CandidateID
JOIN JobPostings j ON r.JobID = j.JobID
LEFT JOIN NetworkStrength ns ON r.ReferrerID = ns.CandidateID 
    AND r.ReferredCandidateID = ns.ConnectionID
LEFT JOIN ReferralPerformance rp ON r.ReferrerID = rp.ReferrerID;
GO

-- View for Market Intelligence Dashboard
CREATE VIEW vw_MarketIntelligenceDashboard AS
SELECT 
    mi.SkillID,
    s.SkillName,
    mi.Location,
    mi.DemandScore,
    mi.SupplyScore,
    mi.DemandScore - mi.SupplyScore AS ImbalanceScore,
    mi.SalaryTrend,
    mi.AvgSalary,
    mi.CompetitorHiringActivity,
    mi.JobPostingsCount,
    mi.CandidateApplicationsCount,
    mi.TimeToFillDays,
    mi.LastUpdated,
    mi.Confidence,
    CASE 
        WHEN mi.DemandScore > 80 AND mi.SupplyScore < 30 THEN 'Critical Shortage'
        WHEN mi.DemandScore > mi.SupplyScore + 20 THEN 'High Demand'
        WHEN ABS(mi.DemandScore - mi.SupplyScore) < 10 THEN 'Balanced'
        WHEN mi.SupplyScore > mi.DemandScore + 20 THEN 'Oversupply'
        ELSE 'Moderate Imbalance'
    END AS MarketCondition,
    CASE 
        WHEN mi.SalaryTrend = 'Rising' AND (mi.DemandScore - mi.SupplyScore) > 15 THEN 'Salary Pressure'
        WHEN mi.SalaryTrend = 'Stable' AND ABS(mi.DemandScore - mi.SupplyScore) < 10 THEN 'Stable Market'
        WHEN mi.SalaryTrend = 'Falling' AND (mi.DemandScore - mi.SupplyScore) < -10 THEN 'Buyer''s Market'
        ELSE 'Normal Conditions'
    END AS SalaryOutlook,
    CASE 
        WHEN mi.TimeToFillDays > 60 THEN 'Very Difficult'
        WHEN mi.TimeToFillDays > 45 THEN 'Difficult'
        WHEN mi.TimeToFillDays > 30 THEN 'Moderate'
        ELSE 'Easy'
    END AS HiringDifficulty
FROM MarketIntelligence mi
JOIN Skills s ON mi.SkillID = s.SkillID
WHERE mi.LastUpdated > DATEADD(MONTH, -3, GETDATE());
GO

