-- Predictive Hiring Score
CREATE PROCEDURE sp_PredictHireSuccess
    @ApplicationID INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @CandidateID INT, @JobID INT;
    DECLARE @SkillMatch DECIMAL(5,2), @ExperienceMatch DECIMAL(5,2);
    DECLARE @InterviewScore DECIMAL(5,2), @ResponseEngagement DECIMAL(5,2);
    DECLARE @HistoricalSuccess DECIMAL(5,2);
    
    SELECT @CandidateID = a.CandidateID, @JobID = a.JobID
    FROM Applications a WHERE a.ApplicationID = @ApplicationID;
    
    SELECT @SkillMatch = 
        CAST(COUNT(CASE WHEN cs.ProficiencyLevel >= js.MinProficiency THEN 1 END) * 100.0 / 
             NULLIF(COUNT(*), 0) AS DECIMAL(5,2))
    FROM JobSkills js
    LEFT JOIN CandidateSkills cs ON js.SkillID = cs.SkillID AND cs.CandidateID = @CandidateID
    WHERE js.JobID = @JobID;
    
    SELECT @ExperienceMatch = 
        CASE 
            WHEN c.YearsOfExperience >= j.MinExperience THEN 100
            ELSE (c.YearsOfExperience * 100.0 / NULLIF(j.MinExperience, 0))
        END
    FROM Candidates c
    CROSS JOIN JobPostings j
    WHERE c.CandidateID = @CandidateID AND j.JobID = @JobID;
    
    SELECT @InterviewScore = ISNULL(AVG(
        (CAST(TechnicalScore AS DECIMAL) + CommunicationScore + CultureFitScore) / 30.0 * 100
    ), 50)
    FROM InterviewFeedback f
    WHERE f.ApplicationID = @ApplicationID;
    
    SELECT @ResponseEngagement = 
        CASE 
            WHEN EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME = 'CommunicationLogs')
            THEN ISNULL((
                SELECT CASE 
                    WHEN AVG(DATEDIFF(HOUR, SentAt, RespondedAt)) < 24 THEN 100
                    WHEN AVG(DATEDIFF(HOUR, SentAt, RespondedAt)) < 48 THEN 75
                    ELSE 50
                END
                FROM CommunicationLogs cl
                WHERE cl.ApplicationID = @ApplicationID AND RespondedAt IS NOT NULL
            ), 60)
            ELSE 70
        END;
    
    SELECT @HistoricalSuccess = ISNULL(
        CAST(SUM(CASE WHEN a2.StatusID = 4 THEN 1 ELSE 0 END) * 100.0 / 
             COUNT(*) AS DECIMAL(5,2)), 
        65
    )
    FROM Applications a2
    WHERE a2.JobID = @JobID 
        AND a2.CandidateID <> @CandidateID
        AND a2.StatusID IN (4, 5);
    
    DECLARE @FinalProbability DECIMAL(5,2);
    SET @FinalProbability = (
        ISNULL(@SkillMatch, 0) * 0.3 +
        ISNULL(@ExperienceMatch, 0) * 0.25 +
        ISNULL(@InterviewScore, 0) * 0.3 +
        ISNULL(@ResponseEngagement, 0) * 0.15
    );
    
    SET @FinalProbability = (@FinalProbability * 0.7 + @HistoricalSuccess * 0.3);
    
    SET @FinalProbability = CASE 
        WHEN @FinalProbability > 100 THEN 100
        WHEN @FinalProbability < 0 THEN 0
        ELSE @FinalProbability
    END;
    
    INSERT INTO AI_Predictions (CandidateID, JobID, ApplicationID, SuccessProbability, KeyFactors)
    VALUES (
        @CandidateID,
        @JobID,
        @ApplicationID,
        @FinalProbability / 100.0,
        JSON_QUERY('{
            "skillMatch": ' + CAST(ISNULL(@SkillMatch, 0) AS VARCHAR) + ',
            "experienceMatch": ' + CAST(ISNULL(@ExperienceMatch, 0) AS VARCHAR) + ',
            "interviewScore": ' + CAST(ISNULL(@InterviewScore, 0) AS VARCHAR) + ',
            "responseEngagement": ' + CAST(ISNULL(@ResponseEngagement, 0) AS VARCHAR) + ',
            "historicalSuccess": ' + CAST(ISNULL(@HistoricalSuccess, 0) AS VARCHAR) + '
        }')
    );
    
    SELECT 
        @FinalProbability AS SuccessProbabilityPercent,
        @FinalProbability / 100.0 AS SuccessProbabilityDecimal,
        CASE 
            WHEN @FinalProbability >= 80 THEN 'High'
            WHEN @FinalProbability >= 60 THEN 'Medium'
            ELSE 'Low'
        END AS ConfidenceLevel,
        ISNULL(@SkillMatch, 0) AS SkillMatchPercent,
        ISNULL(@ExperienceMatch, 0) AS ExperienceMatchPercent,
        ISNULL(@InterviewScore, 0) AS InterviewScorePercent,
        ISNULL(@ResponseEngagement, 0) AS ResponseEngagementPercent,
        ISNULL(@HistoricalSuccess, 0) AS HistoricalSuccessRate;
END
GO

-- Generate Interview Questions
CREATE PROCEDURE sp_GenerateInterviewQuestions
    @JobID INT,
    @QuestionCount INT = 10,
    @DifficultyLevel INT = 5
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @JobSkills TABLE (SkillID INT, SkillName VARCHAR(100), IsMandatory BIT);
    
    INSERT INTO @JobSkills
    SELECT js.SkillID, s.SkillName, js.IsMandatory
    FROM JobSkills js
    JOIN Skills s ON js.SkillID = s.SkillID
    WHERE js.JobID = @JobID;
    
    SELECT TOP (@QuestionCount)
        'Technical' AS QuestionType,
        s.SkillName,
        'Explain your experience with ' + s.SkillName + ' and provide an example project.' AS QuestionText,
        JSON_QUERY('["experience", "project", "implementation", "challenge"]') AS ExpectedKeywords,
        'Assess depth of knowledge, practical application, problem-solving' AS ScoringGuide,
        @DifficultyLevel AS DifficultyLevel,
        CASE WHEN js.IsMandatory = 1 THEN 'High Priority' ELSE 'Medium Priority' END AS Priority
    FROM @JobSkills js
    JOIN Skills s ON js.SkillID = s.SkillID
    WHERE js.IsMandatory = 1
    ORDER BY NEWID();
    
    SELECT 
        'Behavioral' AS QuestionType,
        'General' AS SkillName,
        'Tell me about a time you faced a significant challenge at work and how you overcame it.' AS QuestionText,
        JSON_QUERY('["challenge", "action", "result", "learning"]') AS ExpectedKeywords,
        'Assess problem-solving, resilience, learning ability' AS ScoringGuide,
        @DifficultyLevel AS DifficultyLevel,
        'Standard' AS Priority;
    
    SELECT 
        'Cultural' AS QuestionType,
        'Teamwork' AS SkillName,
        'Describe your ideal work environment and team dynamics.' AS QuestionText,
        JSON_QUERY('["collaboration", "communication", "values", "environment"]') AS ExpectedKeywords,
        'Assess cultural fit, team compatibility, work preferences' AS ScoringGuide,
        @DifficultyLevel AS DifficultyLevel,
        'Standard' AS Priority;
END
GO

-- Consent Expiry Check
CREATE PROCEDURE sp_CheckConsentExpiry
AS
BEGIN
    SET NOCOUNT ON;
    
    UPDATE ConsentManagement
    SET ExpiryDate = DATEADD(DAY, 30, GETDATE())
    WHERE GivenAt < DATEADD(YEAR, -1, GETDATE())
      AND ExpiryDate IS NULL
      AND RevokedAt IS NULL;
    
    UPDATE ConsentManagement
    SET RevokedAt = GETDATE()
    WHERE ExpiryDate < GETDATE()
      AND RevokedAt IS NULL;
    
    PRINT 'Consent expiry check completed.';
END
GO

-- Data Masking Procedure
CREATE PROCEDURE sp_GetMaskedCandidateData
    @UserRole VARCHAR(50),
    @CandidateID INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    IF @UserRole = 'Admin'
    BEGIN
        SELECT 
            c.CandidateID,
            c.FullName,
            u.Email,
            c.Location,
            c.YearsOfExperience,
            c.CreatedAt
        FROM Candidates c
        JOIN Users u ON c.UserID = u.UserID
        WHERE (@CandidateID IS NULL OR c.CandidateID = @CandidateID);
    END
    ELSE IF @UserRole = 'Recruiter'
    BEGIN
        SELECT 
            c.CandidateID,
            c.FullName,
            MaskedEmail = LEFT(u.Email, 3) + '***@' + 
                         SUBSTRING(u.Email, CHARINDEX('@', u.Email) + 1, LEN(u.Email)),
            c.Location,
            c.YearsOfExperience,
            c.CreatedAt
        FROM Candidates c
        JOIN Users u ON c.UserID = u.UserID
        WHERE (@CandidateID IS NULL OR c.CandidateID = @CandidateID);
    END
    ELSE IF @UserRole = 'Analyst'
    BEGIN
        SELECT 
            AnonymizedID = 'CAND_' + CAST(c.CandidateID AS VARCHAR),
            ExperienceGroup = CASE 
                WHEN c.YearsOfExperience < 2 THEN 'Junior'
                WHEN c.YearsOfExperience < 5 THEN 'Mid'
                ELSE 'Senior'
            END,
            LocationGroup = LEFT(c.Location, 3) + '***',
            ApplicationCount = (SELECT COUNT(*) FROM Applications a WHERE a.CandidateID = c.CandidateID),
            AvgInterviewScore = ISNULL((
                SELECT AVG((f.TechnicalScore + f.CommunicationScore + f.CultureFitScore) / 3.0)
                FROM InterviewFeedback f
                JOIN Applications a ON f.ApplicationID = a.ApplicationID
                WHERE a.CandidateID = c.CandidateID
            ), 0)
        FROM Candidates c
        WHERE (@CandidateID IS NULL OR c.CandidateID = @CandidateID);
    END
    ELSE
    BEGIN
        RAISERROR('Invalid user role specified.', 16, 1);
    END
END
GO

-- Automated Screening Bot
CREATE PROCEDURE sp_AutoScreenApplicationEnhanced
    @ApplicationID INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @Score DECIMAL(5,2) = 0;
    DECLARE @MaxScore DECIMAL(5,2) = 100;
    DECLARE @Criteria NVARCHAR(MAX) = '{}';
    DECLARE @CandidateID INT, @JobID INT;
    
    SELECT @CandidateID = a.CandidateID, @JobID = a.JobID
    FROM Applications a WHERE a.ApplicationID = @ApplicationID;
    
    DECLARE @ExperienceScore DECIMAL(5,2);
    SELECT @ExperienceScore = 
        CASE 
            WHEN c.YearsOfExperience >= j.MinExperience THEN 25
            WHEN c.YearsOfExperience >= j.MinExperience * 0.7 THEN 20
            WHEN c.YearsOfExperience >= j.MinExperience * 0.5 THEN 15
            ELSE 10
        END
    FROM Applications a
    JOIN Candidates c ON a.CandidateID = c.CandidateID
    JOIN JobPostings j ON a.JobID = j.JobID
    WHERE a.ApplicationID = @ApplicationID;
    
    SET @Score += @ExperienceScore;
    SET @Criteria = JSON_MODIFY(@Criteria, '$.experienceScore', @ExperienceScore);
    
    DECLARE @SkillsScore DECIMAL(5,2);
    SELECT @SkillsScore = 
        CAST(COUNT(CASE WHEN cs.ProficiencyLevel >= js.MinProficiency THEN 1 END) * 40.0 / 
             NULLIF(SUM(CASE WHEN js.IsMandatory = 1 THEN 1 ELSE 0 END), 0) AS DECIMAL(5,2))
    FROM JobSkills js
    LEFT JOIN CandidateSkills cs ON js.SkillID = cs.SkillID AND cs.CandidateID = @CandidateID
    WHERE js.JobID = @JobID AND js.IsMandatory = 1;
    
    SET @Score += ISNULL(@SkillsScore, 0);
    SET @Criteria = JSON_MODIFY(@Criteria, '$.skillsScore', ISNULL(@SkillsScore, 0));
    
    DECLARE @LocationScore DECIMAL(5,2);
    SELECT @LocationScore = 
        CASE 
            WHEN c.Location = j.Location THEN 20
            WHEN c.Location LIKE '%' + j.Location + '%' THEN 15
            ELSE 10
        END
    FROM Applications a
    JOIN Candidates c ON a.CandidateID = c.CandidateID
    JOIN JobPostings j ON a.JobID = j.JobID
    WHERE a.ApplicationID = @ApplicationID;
    
    SET @Score += @LocationScore;
    SET @Criteria = JSON_MODIFY(@Criteria, '$.locationScore', @LocationScore);
    
    DECLARE @ResumeScore DECIMAL(5,2) = 10;
    IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME = 'ResumeInsights')
    BEGIN
        SELECT @ResumeScore = 
            CASE 
                WHEN ri.ResumeQualityScore >= 80 THEN 15
                WHEN ri.ResumeQualityScore >= 60 THEN 12
                ELSE 8
            END
        FROM ResumeInsights ri
        WHERE ri.CandidateID = @CandidateID
            AND ri.ProcessingStatus = 'Completed';
    END
    
    SET @Score += @ResumeScore;
    SET @Criteria = JSON_MODIFY(@Criteria, '$.resumeScore', @ResumeScore);
    
    DECLARE @Decision VARCHAR(20);
    DECLARE @Confidence DECIMAL(3,2);
    
    SET @Confidence = @Score / @MaxScore;
    SET @Decision = CASE 
        WHEN @Score >= 70 THEN 'Pass'
        WHEN @Score >= 50 THEN 'Maybe'
        WHEN @Score >= 30 THEN 'ManualReview'
        ELSE 'Fail'
    END;
    
    INSERT INTO ScreeningBotDecisions (ApplicationID, Decision, Confidence, Score, CriteriaEvaluated)
    VALUES (@ApplicationID, @Decision, @Confidence, @Score, @Criteria);
    
    SELECT 
        @Decision AS Decision,
        @Confidence AS Confidence,
        @Score AS Score,
        @MaxScore AS MaxScore,
        @Criteria AS CriteriaEvaluated,
        CASE @Decision
            WHEN 'Pass' THEN 'Candidate meets most requirements'
            WHEN 'Maybe' THEN 'Candidate meets some requirements, review recommended'
            WHEN 'ManualReview' THEN 'Requires human evaluation'
            ELSE 'Candidate does not meet minimum requirements'
        END AS DecisionExplanation;
END
GO

-- Generate Learning Path
CREATE PROCEDURE sp_GenerateLearningPath
    @CandidateID INT,
    @TargetJobID INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @SkillsGap NVARCHAR(MAX);
    DECLARE @RecommendedResources NVARCHAR(MAX);
    DECLARE @ReadinessScore INT;
    
    SELECT @SkillsGap = (
        SELECT 
            s.SkillID,
            s.SkillName,
            RequiredLevel = js.MinProficiency,
            CurrentLevel = ISNULL(cs.ProficiencyLevel, 0),
            Gap = js.MinProficiency - ISNULL(cs.ProficiencyLevel, 0),
            Priority = CASE 
                WHEN js.IsMandatory = 1 AND ISNULL(cs.ProficiencyLevel, 0) < js.MinProficiency THEN 'High'
                WHEN js.IsMandatory = 1 THEN 'Medium'
                ELSE 'Low'
            END
        FROM JobSkills js
        JOIN Skills s ON js.SkillID = s.SkillID
        LEFT JOIN CandidateSkills cs ON s.SkillID = cs.SkillID AND cs.CandidateID = @CandidateID
        WHERE js.JobID = @TargetJobID
        ORDER BY 
            CASE WHEN js.IsMandatory = 1 THEN 1 ELSE 2 END,
            Gap DESC
        FOR JSON PATH
    );
    
    SELECT @ReadinessScore = 
        CAST((
            SELECT COUNT(*) 
            FROM JobSkills js
            LEFT JOIN CandidateSkills cs ON js.SkillID = cs.SkillID AND cs.CandidateID = @CandidateID
            WHERE js.JobID = @TargetJobID 
              AND ISNULL(cs.ProficiencyLevel, 0) >= js.MinProficiency
        ) * 100.0 / NULLIF((
            SELECT COUNT(*) FROM JobSkills WHERE JobID = @TargetJobID
        ), 0) AS INT);
    
    SET @RecommendedResources = (
        SELECT 
            'Online Courses' AS ResourceType,
            'Platforms: Coursera, Udemy, edX' AS Description,
            'Focus on skill gaps identified above' AS Guidance
        FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
    );
    
    IF EXISTS (SELECT 1 FROM PersonalizedLearningPaths WHERE CandidateID = @CandidateID AND GoalJobID = @TargetJobID AND IsActive = 1)
    BEGIN
        UPDATE PersonalizedLearningPaths
        SET 
            CurrentReadinessScore = @ReadinessScore,
            SkillsGapAnalysis = @SkillsGap,
            RecommendedResources = @RecommendedResources,
            UpdatedAt = GETDATE()
        WHERE CandidateID = @CandidateID AND GoalJobID = @TargetJobID AND IsActive = 1;
    END
    ELSE
    BEGIN
        INSERT INTO PersonalizedLearningPaths 
        (CandidateID, GoalJobID, CurrentReadinessScore, TargetReadinessScore, SkillsGapAnalysis, RecommendedResources)
        VALUES (@CandidateID, @TargetJobID, @ReadinessScore, 85, @SkillsGap, @RecommendedResources);
    END
    
    SELECT 
        @ReadinessScore AS CurrentReadinessScore,
        85 AS TargetReadinessScore,
        @SkillsGap AS SkillsGapAnalysis,
        @RecommendedResources AS RecommendedResources,
        'Learning path generated successfully. Focus on high-priority skills first.' AS Guidance;
END
GO

-- Generate Interview Preparation
CREATE PROCEDURE sp_GenerateInterviewPrep
    @JobID INT,
    @CandidateID INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @PrepMaterials NVARCHAR(MAX);
    
    DECLARE @JobTitle VARCHAR(150), @Location VARCHAR(100);
    SELECT @JobTitle = JobTitle, @Location = Location FROM JobPostings WHERE JobID = @JobID;
    
    SELECT @PrepMaterials = (
        SELECT 
            'Technical Preparation' AS Category,
            s.SkillName,
            'Study Resources' AS ResourceType,
            'Focus on: ' + s.SkillName + ' concepts and practical applications' AS FocusArea,
            'Expected Depth: Level ' + CAST(js.MinProficiency AS VARCHAR) + '/10' AS ExpectedDepth,
            'Study Time: ' + CAST(js.MinProficiency * 30 AS VARCHAR) + ' minutes' AS RecommendedTime
        FROM JobSkills js
        JOIN Skills s ON js.SkillID = s.SkillID
        WHERE js.JobID = @JobID AND js.IsMandatory = 1
        ORDER BY js.IsMandatory DESC, js.MinProficiency DESC
        FOR JSON PATH
    );
    
    SET @PrepMaterials = JSON_MODIFY(@PrepMaterials, 'append $', 
        JSON_QUERY('{
            "Category": "Behavioral Preparation",
            "SkillName": "Communication",
            "ResourceType": "Mock Interviews",
            "FocusArea": "Common behavioral questions and STAR method responses",
            "ExpectedDepth": "Comprehensive",
            "RecommendedTime": "60 minutes"
        }')
    );
    
    SET @PrepMaterials = JSON_MODIFY(@PrepMaterials, 'append $', 
        JSON_QUERY('{
            "Category": "Company Research",
            "SkillName": "Industry Knowledge",
            "ResourceType": "Company Info",
            "FocusArea": "Company culture, recent news, products/services",
            "ExpectedDepth": "Basic Understanding",
            "RecommendedTime": "45 minutes"
        }')
    );
    
    IF @CandidateID IS NOT NULL
    BEGIN
        DECLARE @CandidateSkills NVARCHAR(MAX);
        SELECT @CandidateSkills = STRING_AGG(s.SkillName, ', ')
        FROM CandidateSkills cs
        JOIN Skills s ON cs.SkillID = s.SkillID
        WHERE cs.CandidateID = @CandidateID AND cs.ProficiencyLevel >= 7;
        
        IF @CandidateSkills IS NOT NULL
        BEGIN
            SET @PrepMaterials = JSON_MODIFY(@PrepMaterials, 'append $', 
                JSON_QUERY('{
                    "Category": "Personalized Tips",
                    "SkillName": "Your Strengths",
                    "ResourceType": "Leverage Points",
                    "FocusArea": "Highlight your expertise in: ' + @CandidateSkills + '",
                    "ExpectedDepth": "Confident Presentation",
                    "RecommendedTime": "30 minutes"
                }')
            );
        END
    END
    
    SELECT 
        @JobTitle AS JobTitle,
        @Location AS Location,
        @PrepMaterials AS InterviewPreparation,
        'Total estimated preparation time: 3-4 hours over 1-2 days' AS OverallGuidance,
        'Day 1: Technical review | Day 2: Behavioral practice & company research' AS SuggestedSchedule;
END
GO

-- Location Match Function
-- FIX-10: Inline table-valued function (set-based, parallelizable)
CREATE FUNCTION dbo.fn_LocationMatch(
    @CandidateLocation VARCHAR(100),
    @JobLocation VARCHAR(100),
    @CandidatePreferences NVARCHAR(MAX) = NULL
)
RETURNS TABLE
AS
RETURN (
    SELECT MatchScore = 
        CASE
            WHEN @CandidateLocation = @JobLocation THEN 1.0
            WHEN @CandidateLocation LIKE '%' + @JobLocation + '%' 
              OR @JobLocation LIKE '%' + @CandidateLocation + '%' THEN 0.7
            WHEN @CandidatePreferences IS NOT NULL 
             AND CHARINDEX(@JobLocation, @CandidatePreferences) > 0 THEN 0.8
            WHEN @JobLocation = 'Remote' THEN 0.9
            ELSE 0.3
        END
);
GO

