-- Fuzzy Candidate Name Search
CREATE PROCEDURE sp_FuzzySearchCandidates
    @SearchName NVARCHAR(100),
    @Threshold FLOAT = 0.85
AS
BEGIN
    SET NOCOUNT ON;
    
    SELECT 
        CandidateID,
        FullName,
        CAST(dbo.JaroWinklerSimilarity(FullName, @SearchName) AS DECIMAL(5,3)) AS JWScore,
        dbo.LevenshteinDistance(FullName, @SearchName) AS LevenDistance
    FROM Candidates
    WHERE dbo.JaroWinklerSimilarity(FullName, @SearchName) >= @Threshold
    ORDER BY JWScore DESC, LevenDistance ASC;
END;
GO

-- Schedule Interview with Timezone Conversion
CREATE PROCEDURE sp_ScheduleInterviewWithTimezone
    @ApplicationID INT,
    @RecruiterID INT,
    @StartTimeUTC DATETIME,
    @EndTimeUTC DATETIME,
    @CandidateTimezone NVARCHAR(100) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @CandidateID INT;
    SELECT @CandidateID = CandidateID FROM Applications WHERE ApplicationID = @ApplicationID;
    
    IF @CandidateTimezone IS NULL
        SELECT @CandidateTimezone = Timezone FROM Candidates WHERE CandidateID = @CandidateID;
    
    IF @CandidateTimezone IS NULL
        SET @CandidateTimezone = 'UTC';
    
    DECLARE @CandidateLocalStart DATETIME = dbo.ConvertTimezone(@StartTimeUTC, 'UTC', @CandidateTimezone);
    DECLARE @CandidateLocalEnd DATETIME = dbo.ConvertTimezone(@EndTimeUTC, 'UTC', @CandidateTimezone);
    
    INSERT INTO InterviewSchedules (ApplicationID, RecruiterID, InterviewStart, InterviewEnd)
    VALUES (@ApplicationID, @RecruiterID, @StartTimeUTC, @EndTimeUTC);
    
    SELECT 
        @@IDENTITY AS ScheduleID,
        @StartTimeUTC AS InterviewStartUTC,
        @EndTimeUTC AS InterviewEndUTC,
        @CandidateLocalStart AS CandidateLocalStart,
        @CandidateLocalEnd AS CandidateLocalEnd,
        @CandidateTimezone AS CandidateTimezone,
        'Interview scheduled. Candidate will see: ' + 
        CONVERT(VARCHAR, @CandidateLocalStart, 100) + ' to ' + 
        CONVERT(VARCHAR, @CandidateLocalEnd, 100) + ' ' + @CandidateTimezone AS Message;
END;
GO

-- Time to Hire in Business Days
CREATE PROCEDURE sp_TimeToHireReport
AS
BEGIN
    SET NOCOUNT ON;
    
    SELECT
        j.JobID,
        j.JobTitle,
        COUNT(a.ApplicationID) AS TotalHires,
        AVG(dbo.CalculateBusinessDays(a.AppliedDate, h.ChangedAt)) AS AvgBusinessDaysToHire,
        MIN(dbo.CalculateBusinessDays(a.AppliedDate, h.ChangedAt)) AS MinBusinessDaysToHire,
        MAX(dbo.CalculateBusinessDays(a.AppliedDate, h.ChangedAt)) AS MaxBusinessDaysToHire
    FROM Applications a
    JOIN JobPostings j ON a.JobID = j.JobID
    JOIN ApplicationStatusHistory h ON a.ApplicationID = h.ApplicationID
    WHERE h.ToStatusID = (SELECT StatusID FROM ApplicationStatus WHERE StatusName = 'Hired')
    GROUP BY j.JobID, j.JobTitle
    ORDER BY AvgBusinessDaysToHire DESC;
END;
GO

-- Interviewer Scoring Consistency Check
CREATE PROCEDURE sp_InterviewerConsistencyCLR
AS
BEGIN
    SET NOCOUNT ON;
    
    SELECT
        f.InterviewerID,
        u.Username AS InterviewerName,
        COUNT(*) AS InterviewCount,
        AVG((f.TechnicalScore + f.CommunicationScore + f.CultureFitScore) / 3.0) AS AvgScore,
        dbo.StandardDeviation(
            (SELECT STRING_AGG(CAST((TechnicalScore + CommunicationScore + CultureFitScore) / 3.0 AS VARCHAR), ',')
             FROM InterviewFeedback WHERE InterviewerID = f.InterviewerID)
        ) AS ScoreStdDev,
        CASE 
            WHEN dbo.StandardDeviation(
                (SELECT STRING_AGG(CAST((TechnicalScore + CommunicationScore + CultureFitScore) / 3.0 AS VARCHAR), ',')
                 FROM InterviewFeedback WHERE InterviewerID = f.InterviewerID)
            ) > 2.5 THEN 'Inconsistent - review scoring calibration'
            ELSE 'Consistent'
        END AS ConsistencyAssessment
    FROM InterviewFeedback f
    JOIN Users u ON f.InterviewerID = u.UserID
    GROUP BY f.InterviewerID, u.Username
    HAVING COUNT(*) >= 3
    ORDER BY ScoreStdDev DESC;
END;
GO

-- Audit Candidate Emails
CREATE PROCEDURE sp_AuditCandidateEmails
AS
BEGIN
    SET NOCOUNT ON;
    
    SELECT
        c.CandidateID,
        c.FullName,
        u.Email,
        dbo.ValidateEmail(u.Email) AS IsValidFormat,
        dbo.IsDisposableEmail(u.Email) AS IsDisposable,
        dbo.ExtractEmailDomain(u.Email) AS Domain,
        CASE 
            WHEN dbo.ValidateEmail(u.Email) = 0 THEN 'Invalid Format'
            WHEN dbo.IsDisposableEmail(u.Email) = 1 THEN 'Disposable Provider'
            ELSE 'OK'
        END AS Status
    FROM Candidates c
    JOIN Users u ON c.UserID = u.UserID
    WHERE dbo.ValidateEmail(u.Email) = 0 OR dbo.IsDisposableEmail(u.Email) = 1
    ORDER BY IsValidFormat ASC, IsDisposable DESC;
END;
GO

-- Process Resume with CLR Parsing
CREATE PROCEDURE sp_ProcessCandidateResume
    @CandidateID INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @ResumeFile VARBINARY(MAX);
    DECLARE @ResumeFileName NVARCHAR(255);
    DECLARE @ResumeText NVARCHAR(MAX);
    DECLARE @ExtractedSkills NVARCHAR(MAX);
    DECLARE @YearsExp INT;
    
    SELECT @ResumeFile = ResumeFile, @ResumeFileName = ResumeFileName
    FROM Candidates
    WHERE CandidateID = @CandidateID;
    
    IF @ResumeFile IS NULL
    BEGIN
        RAISERROR('No resume file found for this candidate.', 16, 1);
        RETURN;
    END
    
    SET @ResumeText = CASE 
        WHEN @ResumeFileName LIKE '%.pdf' THEN dbo.ExtractTextFromPDF(@ResumeFile)
        WHEN @ResumeFileName LIKE '%.docx' THEN dbo.ExtractTextFromDocx(@ResumeFile)
        ELSE NULL
    END;
    
    IF @ResumeText IS NULL
    BEGIN
        RAISERROR('Unsupported resume format. Only PDF and DOCX supported.', 16, 1);
        RETURN;
    END
    
    SET @ExtractedSkills = dbo.ExtractSkills(@ResumeText);
    SET @YearsExp = dbo.ExtractYearsOfExperience(@ResumeText);
    
    UPDATE Candidates
    SET 
        ResumeText = @ResumeText,
        ExtractedSkills = @ExtractedSkills,
        YearsOfExperience = CASE WHEN @YearsExp > 0 THEN @YearsExp ELSE YearsOfExperience END
    WHERE CandidateID = @CandidateID;
    
    SELECT 
        @CandidateID AS CandidateID,
        LEN(@ResumeText) AS TextLength,
        @ExtractedSkills AS ExtractedSkills,
        @YearsExp AS ExtractedYearsOfExperience,
        'Resume processed successfully.' AS Message;
END;
GO

